import { useState, useMemo, useCallback, useEffect } from 'react';
import type { Ayah, RootData } from '../types';
import { normalizeArabicText } from '../utils/text';

const EXPORT_TEMPLATE_KEY = 'qran_app_export_template';
const DEFAULT_EXPORT_TEMPLATE = `ملخص البحث عن: "{{query}}"
- عدد الآيات المطابقة: {{ayah_count}}
- إجمالي التكرارات: {{general_occurrences}}
- المطابقات التامة: {{exact_occurrences}}
- خيار التطابق: {{exact_match_status}}

====================================

{{#results}}
"{{ayah_text}}" (سورة {{surah_name}} - الآية {{ayah_number_in_surah}})

---

{{/results}}
`;

// Helper: Mock data for demonstration until file is loaded
const ROOT_MOCK_DATA: RootData = {
    dictionary: {
        "كتاب": "كتب", "الكتاب": "كتب", "يكتبون": "كتب", "مكتوب": "كتب", "كاتب": "كتب", "كتب": "كتب",
        "رحمة": "رحم", "الرحمن": "رحم", "الرحيم": "رحم", "يرحمون": "رحم"
    },
    // We don't need to mock roots->ayahs fully if we fallback to text scanning in absence of file
    roots: {} 
};

const findNeighboringWords = (results: Ayah[], query: string): string[] => {
    const normalizedQueryWords = normalizeArabicText(query).trim().split(' ').filter(w => w.length > 0);
    const numQueryWords = normalizedQueryWords.length;

    if (numQueryWords === 0 || numQueryWords > 6) {
        return [];
    }

    const freq: { [key: string]: number } = {};
    const addNeighbor = (neighbor: string) => {
        if (neighbor && neighbor.length > 1 && !normalizedQueryWords.includes(neighbor)) {
            freq[neighbor] = (freq[neighbor] || 0) + 1;
        }
    };

    results.forEach(ayah => {
        const ayahWords = normalizeArabicText(ayah.text).split(' ');
        const numAyahWords = ayahWords.length;

        if (numQueryWords === 1) {
            const queryWord = normalizedQueryWords[0];
            ayahWords.forEach((word, index) => {
                if (word === queryWord) {
                    if (index > 0) addNeighbor(ayahWords[index - 1]);
                    if (index < numAyahWords - 1) addNeighbor(ayahWords[index + 1]);
                }
            });
        } else {
            for (let i = 0; i <= numAyahWords - numQueryWords; i++) {
                let match = true;
                for (let j = 0; j < numQueryWords; j++) {
                    if (ayahWords[i + j] !== normalizedQueryWords[j]) {
                        match = false;
                        break;
                    }
                }
                if (match && i + numQueryWords < numAyahWords) {
                    addNeighbor(ayahWords[i + numQueryWords]);
                }
            }
        }
    });

    return Object.entries(freq)
        .sort(([, a], [, b]) => b - a)
        .slice(0, 30)
        .map(([word]) => word);
};


export const useSearchLogic = (
    query: string, 
    correctedQuery: string | undefined, 
    results: Ayah[], 
    searchType: 'text' | 'number',
    quranRoots: RootData | null,
    simpleCleanData: any[] // To perform full scan if root index is partial or missing
) => {
    const [exactMatch, setExactMatch] = useState(false);
    const [isRootSearch, setIsRootSearch] = useState(false);
    const [visibleSuggestionsCount, setVisibleSuggestionsCount] = useState(7);
    const [activePhraseFilter, setActivePhraseFilter] = useState('all');

    const queryWords = useMemo(() => {
        const finalQuery = correctedQuery || query;
        return finalQuery.trim().replace(/"/g, '').split(/\s+/).filter(Boolean).map(normalizeArabicText);
    }, [query, correctedQuery]);

    const isSingleWordSearch = queryWords.length === 1;

    // --- Root Search Logic ---
    const rootResults = useMemo(() => {
        if (!isRootSearch || !isSingleWordSearch || searchType !== 'text') return [];

        const word = queryWords[0];
        // 1. Determine Root
        let root = quranRoots?.dictionary[word] || ROOT_MOCK_DATA.dictionary[word];

        if (!root) {
            // Simple heuristic fallback if dictionary missing (very basic)
            // This is just a fallback, the file should be there
            return [];
        }

        // 2. Find Ayahs
        // Strategy A: Use pre-compiled Index (Fastest)
        if (quranRoots?.roots[root]) {
            const ayahNumbers = new Set(quranRoots.roots[root]);
            // Reconstruct full Ayah objects from simpleCleanData
            const foundAyahs: Ayah[] = [];
            simpleCleanData.forEach(surah => {
                surah.ayahs.forEach((ayah: Ayah) => {
                    if (ayahNumbers.has(ayah.number)) {
                        foundAyahs.push({
                            ...ayah,
                            surah: {
                                number: surah.number, name: surah.name, englishName: surah.englishName,
                                englishNameTranslation: surah.englishNameTranslation, revelationType: surah.revelationType,
                            }
                        });
                    }
                });
            });
            return foundAyahs;
        }

        // Strategy B: Client-side Scan (Slower but works if we only have dictionary)
        // We look for any word in the Quran that maps to the same root
        const foundAyahs: Ayah[] = [];
        simpleCleanData.forEach(surah => {
            surah.ayahs.forEach((ayah: Ayah) => {
                const words = normalizeArabicText(ayah.text).split(' ');
                const hasRootMatch = words.some(w => {
                    const wRoot = quranRoots?.dictionary[w] || ROOT_MOCK_DATA.dictionary[w];
                    return wRoot === root;
                });

                if (hasRootMatch) {
                    foundAyahs.push({
                        ...ayah,
                        surah: {
                            number: surah.number, name: surah.name, englishName: surah.englishName,
                            englishNameTranslation: surah.englishNameTranslation, revelationType: surah.revelationType,
                        }
                    });
                }
            });
        });

        return foundAyahs;

    }, [isRootSearch, isSingleWordSearch, searchType, queryWords, quranRoots, simpleCleanData]);

    const activeResults = isRootSearch ? rootResults : results;

    const phraseFilters = useMemo(() => {
        if (searchType === 'number' || queryWords.length < 2) {
            return [];
        }
        // ... (existing logic, using activeResults instead of results)
        // Note: Phrase filters are usually less relevant for root search, but we keep logic consistent
        const currentResults = activeResults;
        const phrasesToConsider = new Set<string>();
        currentResults.forEach(ayah => {
            const ayahWords = normalizeArabicText(ayah.text).split(' ');
            const indices: number[] = [];
            ayahWords.forEach((word, index) => {
                if (queryWords.includes(word)) {
                    indices.push(index);
                }
            });

            if (indices.length >= queryWords.length) {
                const minIndex = Math.min(...indices);
                const maxIndex = Math.max(...indices);
                if (maxIndex - minIndex < queryWords.length + 3) {
                    const phrase = ayahWords.slice(minIndex, maxIndex + 1).join(' ');
                    phrasesToConsider.add(phrase);
                }
            }
        });

        const userQueryPhrase = queryWords.join(' ');
        phrasesToConsider.add(userQueryPhrase);

        const allPhraseCounts: { phrase: string, count: number }[] = [];
        phrasesToConsider.forEach(phrase => {
            const count = currentResults.filter(ayah => normalizeArabicText(ayah.text).includes(phrase)).length;
            allPhraseCounts.push({ phrase, count });
        });

        const userPhraseObj = allPhraseCounts.find(p => p.phrase === userQueryPhrase);
        const otherPhrases = allPhraseCounts.filter(p => p.phrase !== userQueryPhrase);

        otherPhrases.sort((a, b) => b.count - a.count || a.phrase.length - b.phrase.length);

        const topPhrases = otherPhrases.slice(0, 9);

        const finalFilters = userPhraseObj ? [userPhraseObj, ...topPhrases] : topPhrases;

        return finalFilters.sort((a, b) => b.count - a.count || a.phrase.length - b.phrase.length);
    }, [activeResults, queryWords, searchType]);

    const displayedResults = useMemo(() => {
        let baseResults = activeResults;

        // Exact match applies to Text Mode only, and is mutually exclusive with Root Search logic visually
        if (searchType === 'text' && exactMatch && isSingleWordSearch && !isRootSearch) {
            const normalizedQuery = queryWords.join(' ');
            const regex = new RegExp(`(^|\\s)${normalizedQuery}(\\s|$)`);
            baseResults = baseResults.filter(ayah => regex.test(normalizeArabicText(ayah.text)));
        }

        if (activePhraseFilter === 'all') {
            return baseResults;
        }

        return baseResults.filter(ayah => normalizeArabicText(ayah.text).includes(activePhraseFilter));
    }, [activeResults, queryWords, exactMatch, searchType, activePhraseFilter, isSingleWordSearch, isRootSearch]);

    const occurrencesMap = useMemo(() => {
        if (searchType === 'number' || !query) return [];

        // Use query words logic similar to neighbors, but adapted for highlighting
        // For Root Search: We might want to highlight *all* words of that root.
        // But for MVP, we stick to highlighting the exact query word if present, otherwise just show results.

        const transformedQuery = normalizeArabicText(correctedQuery || query).replace(/"/g, '');
        if (!transformedQuery) return [];

        const occurrences: { itemIndex: number; wordIndex: number; }[] = [];
        const searchTerms = transformedQuery.split(/\s+/);

        displayedResults.forEach((resultAyah, itemIndex) => {
            const ayahWords = normalizeArabicText(resultAyah.text).split(' ');

            for (let i = 0; i <= ayahWords.length - searchTerms.length; i++) {
                const slice = ayahWords.slice(i, i + searchTerms.length);
                if (slice.join(' ') === searchTerms.join(' ')) {
                    occurrences.push({ itemIndex, wordIndex: i });
                }
            }
        });
        return occurrences;
    }, [displayedResults, query, correctedQuery, searchType]);

    const totalOccurrences = occurrencesMap.length;

    const generalOccurrences = useMemo(() => {
        if (searchType === 'number' || queryWords.length === 0) return 0;
        let count = 0;
        activeResults.forEach(ayah => {
            const ayahText = normalizeArabicText(ayah.text);
            queryWords.forEach(word => {
                count += (ayahText.match(new RegExp(word, 'g')) || []).length;
            });
        });
        return count;
    }, [activeResults, queryWords, searchType]);

    const exactOccurrences = useMemo(() => {
        if (searchType === 'number' || queryWords.length === 0) return 0;
        let count = 0;
        const regex = new RegExp(`(^|\\s)(${queryWords.join('|')})(\\s|$)`, 'g');
        activeResults.forEach(ayah => {
            const ayahText = normalizeArabicText(ayah.text);
            count += (ayahText.match(regex) || []).length;
        });
        return count;
    }, [activeResults, queryWords, searchType]);

    const neighboringWords = useMemo(() => {
        if (searchType === 'number' || !isSingleWordSearch) return [];
        return findNeighboringWords(activeResults, correctedQuery || query);
    }, [activeResults, query, correctedQuery, searchType, isSingleWordSearch]);

    const handleShowMore = () => setVisibleSuggestionsCount(prev => prev + 7);

    const formatResultsForExport = useCallback((displayEditionData: any[]): string => {
        if (displayedResults.length === 0) return 'لم يتم العثور على نتائج.';

        const savedTemplate = localStorage.getItem(EXPORT_TEMPLATE_KEY);
        const isTextSearch = searchType === 'text';
        const queryToExport = correctedQuery || query;

        const defaultTemplateForNumber = `ملخص البحث عن الآيات رقم: "{{query}}"
- عدد الآيات التي تم العثور عليها: {{ayah_count}}

====================================

{{#results}}
"{{ayah_text}}" (سورة {{surah_name}} - الآية {{ayah_number_in_surah}})
---
{{/results}}
`;

        const defaultTemplate = isTextSearch ? DEFAULT_EXPORT_TEMPLATE : defaultTemplateForNumber;
        let template = savedTemplate || defaultTemplate;

        template = template.replace(/{{query}}/g, queryToExport);
        template = template.replace(/{{ayah_count}}/g, String(displayedResults.length));

        if (isTextSearch) {
            template = template.replace(/{{general_occurrences}}/g, String(generalOccurrences));
            template = template.replace(/{{exact_occurrences}}/g, String(exactOccurrences));
            template = template.replace(/{{exact_match_status}}/g, exactMatch ? 'مفعل' : 'غير مفعل');
        } else {
            template = template.replace(/-\\s*إجمالي التكرارات:.*?\\n/g, '');
            template = template.replace(/-\\s*المطابقات التامة:.*?\\n/g, '');
            template = template.replace(/-\\s*خيار التطابق:.*?\\n/g, '');
        }

        const resultsRegex = /{{#results}}(.*){{\/results}}/s;
        const match = template.match(resultsRegex);

        if (match && match[1]) {
            const itemTemplate = match[1];
            const allResultsString = displayedResults.map(resultAyah => {
                let itemString = itemTemplate;
                const displaySurah = displayEditionData.find(s => s.number === resultAyah.surah!.number);
                const displayAyah = displaySurah?.ayahs.find(a => a.numberInSurah === resultAyah.numberInSurah);
                const textToExport = displayAyah?.text || resultAyah.text || '';

                itemString = itemString.replace(/{{ayah_text}}/g, textToExport);
                itemString = itemString.replace(/{{surah_name}}/g, resultAyah.surah?.name || '');
                itemString = itemString.replace(/{{ayah_number_in_surah}}/g, String(resultAyah.numberInSurah));
                return itemString;
            }).join('');

            template = template.replace(resultsRegex, allResultsString);
        }

        return template.trim();
    }, [displayedResults, searchType, correctedQuery, query, generalOccurrences, exactOccurrences, exactMatch]);

    // Reset filters when query changes
    useEffect(() => {
        setActivePhraseFilter('all');
        setIsRootSearch(false);
        setExactMatch(false);
        setVisibleSuggestionsCount(7);
    }, [query, correctedQuery]);

    return {
        exactMatch, setExactMatch,
        isRootSearch, setIsRootSearch,
        visibleSuggestionsCount, handleShowMore,
        activePhraseFilter, setActivePhraseFilter,
        queryWords, isSingleWordSearch,
        phraseFilters,
        displayedResults,
        occurrencesMap, totalOccurrences,
        generalOccurrences, exactOccurrences,
        neighboringWords,
        formatResultsForExport,
    };
};

import React, { useState } from 'react';
import type { Ayah } from '../../types';
import { SparklesIcon, TreeIcon } from '../icons';

interface SearchResultsHeaderProps {
    searchType: 'text' | 'number';
    query: string;
    correctedQuery?: string;
    displayedResultsCount: number;
    resultsCount: number;
    isSingleWordSearch: boolean;
    generalOccurrences: number;
    exactOccurrences: number;
    exactMatch: boolean;
    setExactMatch: (value: boolean) => void;
    isRootSearch: boolean;
    setIsRootSearch: (value: boolean) => void;
    totalOccurrences: number;
    onJumpToOccurrence: (target: number) => void;
    cachedAnalysisExists: boolean;
    onNewSearch: (query: string) => void;
}

const SearchResultsHeader: React.FC<SearchResultsHeaderProps> = ({
    searchType, query, correctedQuery, displayedResultsCount, resultsCount,
    isSingleWordSearch, generalOccurrences, exactOccurrences, exactMatch,
    setExactMatch, isRootSearch, setIsRootSearch, totalOccurrences, onJumpToOccurrence, 
    cachedAnalysisExists, onNewSearch
}) => {
    const [jumpToValue, setJumpToValue] = useState('');

    const handleJump = () => {
        const target = parseInt(jumpToValue, 10);
        if (isNaN(target) || target < 1 || target > totalOccurrences) {
            alert(`الرجاء إدخال رقم صحيح بين 1 و ${totalOccurrences}`);
            return;
        }
        onJumpToOccurrence(target);
    };

    const finalQueryForChecks = correctedQuery || query;
    const shouldShowAnalysisButton = finalQueryForChecks.trim().split(/\s+/).filter(Boolean).length === 1 && searchType === 'text';

    return (
        <div className="mb-4 p-4 bg-surface-subtle rounded-lg border border-border-default">
            {correctedQuery && (
                <div className="mb-4 p-4 bg-blue-500/10 border-l-4 border-blue-500 text-text-secondary rounded-r-lg">
                    <p>لم نجد نتائج لـ "{query}". نعرض لك نتائج لأقرب كلمة: <strong>{correctedQuery}</strong>.</p>
                    <button onClick={() => onNewSearch(query)} className="mt-2 text-sm font-bold hover:underline">
                        ابحث عن "{query}" بدلاً من ذلك
                    </button>
                </div>
            )}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div className="flex-grow">
                    {searchType === 'text' ? (
                        <h3 className="text-lg font-semibold text-text-secondary">نتائج البحث عن الكلمات: <span className="font-bold text-primary-text-strong">{(correctedQuery || query).replace(/"/g, '')}</span></h3>
                    ) : (
                        <h3 className="text-lg font-semibold text-text-secondary">الآيات التي تحمل الرقم "<span className="font-bold text-primary-text-strong">{query}</span>"</h3>
                    )}

                    {resultsCount > 0 && (
                        <div className="flex items-center gap-2 mt-2 flex-wrap">
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold bg-green-500/20 text-text-primary shadow-sm cursor-help" title="إجمالي عدد الآيات التي تحتوي على كلمة البحث.">{displayedResultsCount} آيات</span>
                            {searchType === 'text' && isSingleWordSearch && (
                              <>
                                <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold bg-blue-500/20 text-text-primary shadow-sm cursor-help" title="إجمالي عدد مرات ورود كلمة البحث في كل الآيات.">{generalOccurrences} تكراراً</span>

                                <button
                                    onClick={() => {
                                        setExactMatch(!exactMatch);
                                        if (!exactMatch) setIsRootSearch(false);
                                    }}
                                    className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold shadow-sm transition-all duration-200 cursor-pointer focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-surface-subtle focus:ring-purple-500
                                    ${exactMatch 
                                        ? 'bg-purple-600 text-white' 
                                        : 'bg-purple-500/20 text-text-primary hover:bg-purple-500/40'}`}
                                    title="تفعيل/إلغاء تفعيل المطابقة التامة"
                                    aria-pressed={exactMatch}
                                >
                                    {exactOccurrences} مطابقة
                                </button>

                                <button
                                    onClick={() => {
                                        setIsRootSearch(!isRootSearch);
                                        if (!isRootSearch) setExactMatch(false);
                                    }}
                                    className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-semibold shadow-sm transition-all duration-200 cursor-pointer focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-surface-subtle focus:ring-amber-500
                                    ${isRootSearch
                                        ? 'bg-amber-600 text-white' 
                                        : 'bg-amber-500/20 text-text-primary hover:bg-amber-500/40'}`}
                                    title="البحث عن جميع الكلمات التي تشترك في نفس الجذر اللغوي"
                                    aria-pressed={isRootSearch}
                                >
                                    <TreeIcon className="w-4 h-4" />
                                    <span>البحث بالجذر</span>
                                </button>
                              </>
                            )}
                        </div>
                    )}
                </div>
            </div>
            {searchType === 'text' && totalOccurrences > 1 && (
                <div className="mt-3 pt-3 border-t border-border-default flex items-center gap-2 flex-wrap">
                    <label htmlFor="jump-input" className="text-sm font-semibold text-text-muted">الانتقال إلى التكرار:</label>
                    <input id="jump-input" type="number" value={jumpToValue} onChange={(e) => setJumpToValue(e.target.value)} min="1" max={totalOccurrences} className="w-24 p-1.5 border border-border-default rounded-md text-center bg-surface focus:outline-none focus:ring-2 focus:ring-primary" placeholder={`1 - ${totalOccurrences}`} />
                    <button onClick={handleJump} className="px-4 py-1.5 bg-primary text-white text-sm font-semibold rounded-md hover:bg-primary-hover transition-colors">اذهب</button>
                </div>
            )}
            {cachedAnalysisExists && shouldShowAnalysisButton && (
                <div className="mt-3 pt-3 border-t border-border-default">
                    <a href={`#/analysis/${encodeURIComponent(finalQueryForChecks)}`} onClick={(e) => { e.preventDefault(); window.location.hash = `#/analysis/${encodeURIComponent(finalQueryForChecks)}`; }} className="inline-flex items-center gap-2 px-4 py-2 bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 font-semibold rounded-md hover:bg-blue-200 dark:hover:bg-blue-800/60 transition-colors">
                        <SparklesIcon className="w-5 h-5" />
                        <span>عرض التحليل المحفوظ لهذه الكلمة</span>
                    </a>
                </div>
            )}
        </div>
    );
};

export default SearchResultsHeader;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import type { Ayah, SurahData, QuranEdition, SavedAyahItem, SavedSearchItem, FontSize, FontStyleType, RootData } from '../types';
import { SearchIcon, ClearIcon, BackspaceIcon, BackspaceReverseIcon } from './icons';
import { normalizeArabicText, formatSurahNameForDisplay } from '../utils/text';
import { useSearchLogic } from '../hooks/useSearchLogic';
import { db } from '../firebase';

import DiscussionSection from './DiscussionSection';
import AyahActionPopover from './AyahActionPopover';
import SearchResultItem from './SearchResultItem';
import SearchResultsHeader from './search/SearchResultsHeader';
import SearchResultsToolbar from './search/SearchResultsToolbar';
import PhraseFilters from './search/PhraseFilters';
import NeighboringWords from './search/NeighboringWords';


interface SearchViewProps {
  query: string;
  results: Ayah[];
  onNewSearch: (word: string, sourceEdition?: string, position?: { surah: number, ayah: number, wordIndex: number }) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  onSearchComplete: () => void;
  autoOpenDiscussion?: boolean;
  displayEdition: QuranEdition;
  displayEditionData: SurahData[];
  searchEdition: string;
  fontSize: FontSize;
  fontStyle: FontStyleType;
  position?: { surah: number, ayah: number, wordIndex: number };
  simpleCleanData: SurahData[];
  onSaveAyah: (item: SavedAyahItem) => void;
  onSaveSearch: (item: SavedSearchItem) => void;
  searchType?: 'text' | 'number';
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  correctedQuery?: string;
  quranRoots: RootData | null;
}

export const SearchView: React.FC<SearchViewProps> = ({ 
    query, results, onNewSearch, onSearchByAyahNumber, onSearchComplete, autoOpenDiscussion, 
    displayEdition, displayEditionData, searchEdition, fontSize, fontStyle, position, 
    simpleCleanData, onSaveAyah, onSaveSearch, searchType = 'text',
    currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
    allAudioEditions, selectedAudioEdition, onAudioEditionChange,
    correctedQuery, quranRoots
}) => {
  const [editableQuery, setEditableQuery] = useState(query);
  const [isAllCopied, setIsAllCopied] = useState(false);

  const itemRefs = useRef<React.RefObject<HTMLLIElement>[]>([]);

  const [wordPopoverState, setWordPopoverState] = useState<{
    resultIndex: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [cachedAnalysisExists, setCachedAnalysisExists] = useState(false);
  const [pulsingWord, setPulsingWord] = useState<{ itemIndex: number; wordIndex: number } | null>(null);

  const {
    exactMatch, setExactMatch,
    isRootSearch, setIsRootSearch,
    visibleSuggestionsCount, handleShowMore,
    activePhraseFilter, setActivePhraseFilter,
    queryWords, isSingleWordSearch,
    phraseFilters,
    displayedResults,
    occurrencesMap, totalOccurrences,
    generalOccurrences, exactOccurrences,
    neighboringWords,
    formatResultsForExport,
  } = useSearchLogic(query, correctedQuery, results, searchType as 'text' | 'number', quranRoots, simpleCleanData);


  const normalizedQueryForDiscussion = useMemo(() => {
    if (searchType === 'number') return `topic:ayah-number:${query}`;
    return normalizeArabicText(correctedQuery || query);
  }, [query, correctedQuery, searchType]);

  useEffect(() => { setEditableQuery(query); }, [query]);
  useEffect(() => { onSearchComplete(); }, [results, onSearchComplete]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(event.target as Node)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
        if (!(event.target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const checkAnalysisCache = async () => {
        const trimmedQuery = (correctedQuery || query).trim();
        const isSingleWord = trimmedQuery.split(/\s+/).length === 1 && trimmedQuery.length > 1;
        if (isSingleWord && searchType === 'text') {
            setCachedAnalysisExists(false);
            try {
                const snapshot = await db.collection('qran_word_analysis_cache').doc(normalizeArabicText(trimmedQuery)).collection('analyses').limit(1).get();
                if (!snapshot.empty) setCachedAnalysisExists(true);
            } catch (error) { console.error("Error checking analysis cache:", error); }
        } else {
            setCachedAnalysisExists(false);
        }
    };
    checkAnalysisCache();
  }, [query, correctedQuery, searchType]);

  itemRefs.current = displayedResults.map((_, i) => itemRefs.current[i] ?? React.createRef());

  useEffect(() => {
    if (currentlyPlayingAyahGlobalNumber) {
        const playingIndex = displayedResults.findIndex(ayah => ayah.number === currentlyPlayingAyahGlobalNumber);
        if (playingIndex !== -1 && itemRefs.current[playingIndex]?.current) {
            itemRefs.current[playingIndex].current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }
  }, [currentlyPlayingAyahGlobalNumber, displayedResults]);

  const handleJumpToOccurrence = (target: number) => {
    const occurrence = occurrencesMap[target - 1];
    if (occurrence && itemRefs.current[occurrence.itemIndex]?.current) {
        const element = itemRefs.current[occurrence.itemIndex].current;
        element?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        setPulsingWord({ itemIndex: occurrence.itemIndex, wordIndex: occurrence.wordIndex });
        setTimeout(() => setPulsingWord(null), 3000);
    }
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedQuery = editableQuery.trim();
    if (trimmedQuery && trimmedQuery !== query) onNewSearch(trimmedQuery);
  };

  const handleDeleteFirstChar = () => {
    const newQuery = editableQuery.slice(1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleDeleteLastChar = () => {
    const newQuery = editableQuery.slice(0, -1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleSaveSearch = () => {
    const queryToSave = correctedQuery || query;
    if (queryToSave) onSaveSearch({ type: 'search', id: queryToSave, query: queryToSave, createdAt: Date.now() });
  };

  const handleCopyAll = () => {
    const textToCopy = formatResultsForExport(displayEditionData);
    if (textToCopy) navigator.clipboard.writeText(textToCopy).then(() => {
        setIsAllCopied(true);
        setTimeout(() => setIsAllCopied(false), 2500);
    });
  };

  const handleDownloadAll = () => {
    const textToDownload = formatResultsForExport(displayEditionData);
    if (textToDownload) {
        const blob = new Blob([textToDownload], { type: 'text/plain;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        const safeQuery = (correctedQuery || query).replace(/[^a-zA-Z0-9-ء-ي ]/g, "").trim() || 'results';
        link.download = `qran-top-search-${safeQuery}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
    }
  };

  const handlePlayAll = () => {
    if (displayedResults.length > 0) onStartPlayback(displayedResults, selectedAudioEdition);
  };

  // --- Ayah Action Handlers ---
  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({ type: 'ayah', id: `${ayah.surah!.number}:${ayah.numberInSurah}`, surah: ayah.surah!.number, ayah: ayah.numberInSurah, text: ayah.text || '', createdAt: Date.now() });
    setActivePopover(null);
  };
  const handleCopyAyah = (ayah: Ayah) => {
    const isImlaei = fontStyle === 'imlai_1' || fontStyle === 'imlai_2';
    let ayahText = ayah.text || '';

    if (isImlaei) {
        const marksToRemoveRegex = /[\u06D6-\u06ED]/g;
        ayahText = ayahText.replace(marksToRemoveRegex, '');
    }

    const textToCopy = `"${ayahText}" (سورة ${formatSurahNameForDisplay(ayah.surah?.name)} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };
  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah!.number);
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    if (simpleAyah?.text) onNewSearch(simpleAyah.text, 'quran-simple-clean', { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    else if (ayah.text) onNewSearch(ayah.text, displayEdition.identifier, { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    setActivePopover(null);
  };
  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = results.findIndex(a => a.number === ayah.number);
    if (startIndex !== -1) onStartPlayback(results, selectedAudioEdition, startIndex);
    setActivePopover(null);
  };

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {searchType !== 'number' && (
          <div className="mb-6">
              <form onSubmit={handleFormSubmit} className="flex-grow w-full flex items-center gap-2">
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteFirstChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من بداية الكلمة"><BackspaceIcon className="w-5 h-5" /></button>}
                <div className="relative flex-grow">
                    <input type="text" value={editableQuery} onChange={(e) => setEditableQuery(e.target.value)} placeholder="ابحث عن كلمة..." className="w-full text-xl font-bold text-primary-text-strong border-b-2 border-border-default focus:border-primary bg-transparent py-2 pr-4 pl-12 outline-none transition-colors" aria-label="كلمة البحث"/>
                    {editableQuery && (<button type="button" onClick={() => { setEditableQuery(''); onNewSearch(''); }} className="absolute left-1 top-1/2 -translate-y-1/2 p-2 text-text-muted hover:text-text-primary rounded-full" aria-label="مسح البحث"><ClearIcon className="w-5 h-5" /></button>)}
                </div>
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteLastChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من نهاية الكلمة"><BackspaceReverseIcon className="w-5 h-5" /></button>}
                <button type="submit" className="flex-shrink-0 p-3 bg-primary text-white rounded-full hover:bg-primary-hover transition-colors focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50" aria-label="بحث"><SearchIcon className="w-5 h-5" /></button>
            </form>
            <NeighboringWords neighboringWords={neighboringWords} visibleSuggestionsCount={visibleSuggestionsCount} onNeighborClick={(word) => onNewSearch(`${editableQuery.trim()} ${word}`)} onShowMore={handleShowMore}/>
          </div>
      )}

      <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
        <PhraseFilters phraseFilters={phraseFilters} activePhraseFilter={activePhraseFilter} setActivePhraseFilter={setActivePhraseFilter} resultsCount={displayedResults.length}/>
        <SearchResultsHeader 
            searchType={searchType} query={query} correctedQuery={correctedQuery}
            displayedResultsCount={displayedResults.length} resultsCount={results.length}
            isSingleWordSearch={isSingleWordSearch} generalOccurrences={generalOccurrences}
            exactOccurrences={exactOccurrences} exactMatch={exactMatch} setExactMatch={setExactMatch}
            isRootSearch={isRootSearch} setIsRootSearch={setIsRootSearch}
            totalOccurrences={totalOccurrences} onJumpToOccurrence={handleJumpToOccurrence}
            cachedAnalysisExists={cachedAnalysisExists} onNewSearch={onNewSearch}
        />

        {displayedResults.length > 0 && (
          <>
            <SearchResultsToolbar
                isPlaybackLoading={isPlaybackLoading} allAudioEditions={allAudioEditions}
                onPlayAll={handlePlayAll} selectedAudioEdition={selectedAudioEdition}
                onAudioEditionChange={onAudioEditionChange} searchType={searchType}
                onSaveSearch={handleSaveSearch} onCopyAll={handleCopyAll}
                isAllCopied={isAllCopied} onDownloadAll={handleDownloadAll}
            />
            <DiscussionSection topicId={normalizedQueryForDiscussion} wordForTopic={correctedQuery || query} autoOpen={autoOpenDiscussion} showAnalysisButton={isSingleWordSearch} onAnalysisClick={() => window.location.hash = `#/analysis/${encodeURIComponent(correctedQuery || query)}`}/>
          </>
        )}

        <div className="mt-6">
            {displayedResults.length > 0 ? (
                <ul className="space-y-4">
                    {displayedResults.map((ayah, index) => {
                        const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah?.number);
                        const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
                        return (
                           <SearchResultItem 
                                key={ayah.number} itemRef={itemRefs.current[index]} ayah={ayah} 
                                queryWords={searchType === 'number' ? [] : queryWords} onNewSearch={onNewSearch}
                                displayEdition={displayEdition} displayEditionData={displayEditionData} searchEdition={searchEdition}
                                fontSize={fontSize} fontStyle={fontStyle} searchType={searchType} isCurrentlyPlaying={ayah.number === currentlyPlayingAyahGlobalNumber}
                                pulsingWordIndex={pulsingWord?.itemIndex === index ? pulsingWord.wordIndex : -1} resultIndex={index}
                                simpleAyahText={simpleAyah?.text || ''}
                                onUthmaniWordClick={(e, idx, text) => { if (wordPopoverState?.resultIndex === idx) setWordPopoverState(null); else setWordPopoverState({ resultIndex: idx, simpleText: text, triggerElement: e.currentTarget }); }}
                                onOpenPopover={(ayah, triggerElement) => setActivePopover({ ayah, triggerElement })}
                            />
                       );
                    })}
                </ul>
            ) : (<div className="text-center p-10 text-lg text-text-muted">لم يتم العثور على نتائج.</div>)}
        </div>
      </main>

       {wordPopoverState && (
         <div ref={wordPopoverRef} className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return { top: `${rect.bottom + window.scrollY + 5}px`, left: `${rect.left + window.scrollX + rect.width / 2}px`, transform: 'translateX(-50%)' };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, wordIndex) => {
                const originalAyah = displayedResults[wordPopoverState.resultIndex];
                return (
                    <button key={wordIndex} onClick={() => { onNewSearch(word, 'quran-simple-clean', { surah: originalAyah.surah!.number, ayah: originalAyah.numberInSurah, wordIndex: wordIndex }); setWordPopoverState(null); }} className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors">
                        {word}
                    </button>
                );
            })}
        </div>
      )}

       {activePopover && <AyahActionPopover activePopover={activePopover} onClose={() => setActivePopover(null)} onSave={handleSaveClick} onCopy={handleCopyAyah} onSearchText={handleSearchByAyahText} onSearchNumber={onSearchByAyahNumber} onPlayFrom={handlePlayFromAyah} copiedAyah={copiedAyah} />}
    </div>
  );
};

import React from 'react';
import type { Ayah, SurahData, Collections, QuranEdition, SavedItem, FontSize, BrowsingMode, FontStyleType, RootData } from '../types';

import HomeView from './HomeView';
import SurahDetailView from './SurahDetailView';
import { SearchView } from './SearchView';
import SettingsView from './SettingsView';
import SavedView from './SavedView';
import KhatmiyahView from './KhatmiyahView';
import AudioKhatmiyahView from './AudioKhatmiyahView';
import AdminView from './AdminView';
import CommentsCloudView from './CommentsCloudView';
import WordAnalysisView from './WordAnalysisView';
import PrivacyPolicyView from './PrivacyPolicyView';
import LoadingScreen from './LoadingScreen';
import AboutView from './AboutView';

import { QURAN_INDEX } from '../quranIndex';
import { JUZ_INDEX, HIZB_INDEX } from '../quranPartitions';

interface AppRouterProps {
    pathParts: string[];
    queryParams: URLSearchParams;
    isInitialLoading: boolean;
    quranData: SurahData[] | undefined;
    simpleSearchableAyahs: Ayah[];
    collections: Collections;
    audioKhatmiyahProgress: { ayahNumber: number } | null;
    handleSaveAudioKhatmiyahProgress: (ayahNumber: number) => void;
    ALL_AUDIO_EDITIONS: QuranEdition[];
    selectedAudioEdition: string;
    setSelectedAudioEdition: (id: string) => void;
    allQuranData: { [key: string]: SurahData[] } | null;
    fetchCustomEditionData: (id: string) => void;
    fontSize: FontSize;
    setFontSize: (size: FontSize) => void;
    fontStyle: FontStyleType;
    activeEditions: QuranEdition[];
    selectedEdition: string;
    setSelectedEdition: (id: string) => void;
    handleDeleteCollection: (id: string) => void;
    handleDeleteSavedItem: (collectionId: string, itemId: string) => void;
    updateItemNotes: (collectionId: string, itemId: string, notes: string) => void;
    handleExportNotebook: () => Promise<string>;
    handleImportNotebook: (code: string) => Promise<void>;
    handleSearch: (query: string, sourceEdition?: string, position?: { surah: number; ayah: number; wordIndex: number; }) => void;
    displayEdition: QuranEdition;
    browsingMode: BrowsingMode;
    handleSaveItem: (item: SavedItem) => void;
    handleSearchByAyahNumber: (num: number) => void;
    currentlyPlayingAyahGlobalNumber: number | null;
    playbackInfo: any;
    handleStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
    hizbQuarterStartMap: Map<number, number>;
    setIsSearching: (isSearching: boolean) => void;
    performSearchByAyahNumber: (num: number) => Ayah[];
    performSearch: (query: string) => { results: Ayah[], finalSearchEdition: string, correctedQuery?: string };
    quranRoots: RootData | null;
}

const AppRouter: React.FC<AppRouterProps> = (props) => {
    const {
        pathParts, queryParams, isInitialLoading, quranData, simpleSearchableAyahs, collections,
        audioKhatmiyahProgress, handleSaveAudioKhatmiyahProgress, ALL_AUDIO_EDITIONS,
        selectedAudioEdition, setSelectedAudioEdition, allQuranData, fetchCustomEditionData,
        fontSize, setFontSize, fontStyle, activeEditions, selectedEdition, setSelectedEdition,
        handleDeleteCollection, handleDeleteSavedItem, updateItemNotes, handleExportNotebook,
        handleImportNotebook, handleSearch, displayEdition, browsingMode, handleSaveItem,
        handleSearchByAyahNumber, currentlyPlayingAyahGlobalNumber, playbackInfo, handleStartPlayback,
        hizbQuarterStartMap, setIsSearching, performSearchByAyahNumber, performSearch,
        quranRoots
    } = props;

    if (isInitialLoading) return <LoadingScreen />;
    if (pathParts[0] === 'admin') return <AdminView />;
    if (pathParts[0] === 'khatmiyah') return <KhatmiyahView khatmiyahId={pathParts[1] || null} />;
    if (pathParts[0] === 'audio-khatmiyah') {
        return <AudioKhatmiyahView
            allAyahs={simpleSearchableAyahs}
            allAudioEditions={ALL_AUDIO_EDITIONS}
            initialAyahNumber={audioKhatmiyahProgress?.ayahNumber || 1}
            onSaveProgress={handleSaveAudioKhatmiyahProgress}
            selectedAudioEdition={selectedAudioEdition}
            onAudioEditionChange={setSelectedAudioEdition}
            allQuranData={allQuranData}
            fetchCustomEditionData={fetchCustomEditionData}
            activeEditions={activeEditions}
        />;
    }
    if (pathParts[0] === 'saved') return <SavedView collections={collections} collectionId={pathParts[1] || null} onDeleteCollection={handleDeleteCollection} onDeleteSavedItem={handleDeleteSavedItem} onUpdateNotes={updateItemNotes} />;
    if (pathParts[0] === 'analysis') return <WordAnalysisView simpleCleanData={allQuranData?.['quran-simple-clean'] || []} initialWord={pathParts[1] ? decodeURIComponent(pathParts[1]) : undefined} />;
    if (pathParts[0] === 'settings') return <SettingsView 
        onExportNotebook={handleExportNotebook} 
        onImportNotebook={handleImportNotebook}
    />;
    if (pathParts[0] === 'about') return <AboutView />;
    if (pathParts[0] === 'privacy-policy') return <PrivacyPolicyView />;

    // Handle Page Route
    if (pathParts[0] === 'page' && pathParts[1]) {
        if (isInitialLoading || !quranData) {
            return null;
        }
        const pageNumber = parseInt(pathParts[1], 10);

        // Collect ALL Surahs that have ayahs on this page
        const pageSurahs: SurahData[] = [];
        let startAyahInFirstSurah: number | null = null;

        for (const surah of quranData) {
            const ayahsOnPage = surah.ayahs.filter(a => a.page === pageNumber);
            if (ayahsOnPage.length > 0) {
                // We create a "Partial Surah" object containing only the ayahs for this page
                pageSurahs.push({
                    ...surah,
                    ayahs: ayahsOnPage
                });

                if (startAyahInFirstSurah === null) {
                    startAyahInFirstSurah = ayahsOnPage[0].numberInSurah;
                }
            }
        }

        if (pageSurahs.length > 0) {
            // We pass the first surah as the 'main' surah prop for context, 
            // but we pass the array of pageSurahs for the actual rendering.
            return <SurahDetailView 
                surah={pageSurahs[0]}
                pageSurahs={pageSurahs} // Pass the collected surahs
                highlightAyahNumber={startAyahInFirstSurah}
                onWordClick={handleSearch}
                displayEdition={displayEdition}
                fontSize={fontSize}
                fontStyle={fontStyle}
                browsingMode={'page'} // Force page mode
                onSaveAyah={handleSaveItem}
                onSearchByAyahNumber={handleSearchByAyahNumber}
                currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                onStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                selectedAudioEdition={selectedAudioEdition}
                simpleCleanData={allQuranData?.['quran-simple-clean'] || []}
                hizbQuarterStartMap={hizbQuarterStartMap}
                forcedPageNumber={pageNumber} // Explicitly pass the page number
            />;
        } else {
             return <div className="text-center p-10">الصفحة غير موجودة</div>;
        }
    }

    if (pathParts[0] === 'surah' && pathParts[1]) {
        if (isInitialLoading || !quranData) {
            return null;
        }
        const surahNumber = parseInt(pathParts[1], 10);
        const highlightAyahNumber = queryParams.get('ayah') ? parseInt(queryParams.get('ayah')!, 10) : null;
        const surah = quranData.find(s => s.number === surahNumber);
        if (surah) {
            return <SurahDetailView 
                surah={surah}
                highlightAyahNumber={highlightAyahNumber}
                onWordClick={handleSearch}
                displayEdition={displayEdition}
                fontSize={fontSize}
                browsingMode={browsingMode}
                fontStyle={fontStyle}
                onSaveAyah={handleSaveItem}
                onSearchByAyahNumber={handleSearchByAyahNumber}
                currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                onStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                selectedAudioEdition={selectedAudioEdition}
                simpleCleanData={allQuranData?.['quran-simple-clean'] || []}
                hizbQuarterStartMap={hizbQuarterStartMap}
            />;
        }
    }
    if (pathParts[0] === 'search') {
        const commonProps = {
            onNewSearch: handleSearch, onSearchByAyahNumber: handleSearchByAyahNumber,
            onSearchComplete: () => setIsSearching(false), displayEdition: displayEdition,
            displayEditionData: quranData || [], 
            fontSize: fontSize, fontStyle: fontStyle, simpleCleanData: allQuranData?.['quran-simple-clean'] || [],
            onSaveAyah: handleSaveItem, onSaveSearch: handleSaveItem,
            currentlyPlayingAyahGlobalNumber: currentlyPlayingAyahGlobalNumber, isPlaybackLoading: !!playbackInfo?.trigger,
            onStartPlayback: handleStartPlayback, allAudioEditions: ALL_AUDIO_EDITIONS,
            selectedAudioEdition: selectedAudioEdition, onAudioEditionChange: setSelectedAudioEdition,
            quranRoots: quranRoots,
        };
        if (pathParts[1] === 'number' && pathParts[2]) {
            const ayahNumber = parseInt(pathParts[2], 10);
            return <SearchView {...commonProps} query={pathParts[2]} results={performSearchByAyahNumber(ayahNumber)} searchEdition={'quran-simple-clean'} searchType="number" />;
        }
        const query = pathParts[1] ? decodeURIComponent(pathParts[1]) : "";
        const searchResult = performSearch(query);
        const position = queryParams.get('s') ? { surah: parseInt(queryParams.get('s')!), ayah: parseInt(queryParams.get('a')!), wordIndex: parseInt(queryParams.get('w')!) } : undefined;
        return <SearchView {...commonProps} query={query} results={searchResult.results} correctedQuery={searchResult.correctedQuery} autoOpenDiscussion={!!queryParams.get('from')} searchEdition={searchResult.finalSearchEdition} position={position} />;
    }
    if (pathParts[0] === 'comments') return <CommentsCloudView />;

    return <HomeView surahList={QURAN_INDEX} juzList={JUZ_INDEX} hizbList={HIZB_INDEX} />;
};

export default AppRouter;

