    const {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions,
        fetchCustomEditionData, dataSourceStatus, error: dataError, quranRoots
    } = useQuranData();

    const { currentPath, pathParts, queryParams } = useRouting();

    const {
        fontSize, setFontSize,
        fontStyle, setFontStyle,
        browsingMode, setBrowsingMode, activeEditions, selectedEdition,
        setSelectedEdition, selectedAudioEdition, setSelectedAudioEdition,
