import { useState, useMemo, useCallback, useEffect } from 'react';
import type { Ayah } from '../types';
import { normalizeArabicText } from '../utils/text';

const EXPORT_TEMPLATE_KEY = 'qran_app_export_template';
const DEFAULT_EXPORT_TEMPLATE = `ملخص البحث عن: "{{query}}"
- عدد الآيات المطابقة: {{ayah_count}}
- إجمالي التكرارات: {{general_occurrences}}
- المطابقات التامة: {{exact_occurrences}}
- خيار التطابق: {{exact_match_status}}

====================================

{{#results}}
"{{ayah_text}}" (سورة {{surah_name}} - الآية {{ayah_number_in_surah}})

---

{{/results}}
`;

const findNeighboringWords = (results: Ayah[], query: string): string[] => {
    const normalizedQueryWords = normalizeArabicText(query).trim().split(' ').filter(w => w.length > 0);
    const numQueryWords = normalizedQueryWords.length;

    if (numQueryWords === 0 || numQueryWords > 6) {
        return [];
    }

    const freq: { [key: string]: number } = {};
    const addNeighbor = (neighbor: string) => {
        if (neighbor && neighbor.length > 1 && !normalizedQueryWords.includes(neighbor)) {
            freq[neighbor] = (freq[neighbor] || 0) + 1;
        }
    };

    results.forEach(ayah => {
        const ayahWords = normalizeArabicText(ayah.text).split(' ');
        const numAyahWords = ayahWords.length;

        if (numQueryWords === 1) {
            const queryWord = normalizedQueryWords[0];
            ayahWords.forEach((word, index) => {
                if (word === queryWord) {
                    if (index > 0) addNeighbor(ayahWords[index - 1]);
                    if (index < numAyahWords - 1) addNeighbor(ayahWords[index + 1]);
                }
            });
        } else {
            for (let i = 0; i <= numAyahWords - numQueryWords; i++) {
                let match = true;
                for (let j = 0; j < numQueryWords; j++) {
                    if (ayahWords[i + j] !== normalizedQueryWords[j]) {
                        match = false;
                        break;
                    }
                }
                if (match && i + numQueryWords < numAyahWords) {
                    addNeighbor(ayahWords[i + numQueryWords]);
                }
            }
        }
    });

    return Object.entries(freq)
        .sort(([, a], [, b]) => b - a)
        .slice(0, 30)
        .map(([word]) => word);
};


export const useSearchLogic = (
    query: string, 
    correctedQuery: string | undefined, 
    results: Ayah[], 
    searchType: 'text' | 'number',
    simpleCleanData: any[]
) => {
    const [exactMatch, setExactMatch] = useState(false);
    const [visibleSuggestionsCount, setVisibleSuggestionsCount] = useState(7);
    const [activePhraseFilter, setActivePhraseFilter] = useState('all');

    const queryWords = useMemo(() => {
        const finalQuery = correctedQuery || query;
        return finalQuery.trim().replace(/"/g, '').split(/\s+/).filter(Boolean).map(normalizeArabicText);
    }, [query, correctedQuery]);

    const isSingleWordSearch = queryWords.length === 1;

    const activeResults = results;

    const phraseFilters = useMemo(() => {
        if (searchType === 'number' || queryWords.length < 2) {
            return [];
        }

        const currentResults = activeResults;
        const phrasesToConsider = new Set<string>();
        currentResults.forEach(ayah => {
            const ayahWords = normalizeArabicText(ayah.text).split(' ');
            const indices: number[] = [];
            ayahWords.forEach((word, index) => {
                if (queryWords.includes(word)) {
                    indices.push(index);
                }
            });

            if (indices.length >= queryWords.length) {
                const minIndex = Math.min(...indices);
                const maxIndex = Math.max(...indices);
                if (maxIndex - minIndex < queryWords.length + 3) {
                    const phrase = ayahWords.slice(minIndex, maxIndex + 1).join(' ');
                    phrasesToConsider.add(phrase);
                }
            }
        });

        const userQueryPhrase = queryWords.join(' ');
        phrasesToConsider.add(userQueryPhrase);

        const allPhraseCounts: { phrase: string, count: number }[] = [];
        phrasesToConsider.forEach(phrase => {
            const count = currentResults.filter(ayah => normalizeArabicText(ayah.text).includes(phrase)).length;
            allPhraseCounts.push({ phrase, count });
        });

        const userPhraseObj = allPhraseCounts.find(p => p.phrase === userQueryPhrase);
        const otherPhrases = allPhraseCounts.filter(p => p.phrase !== userQueryPhrase);

        otherPhrases.sort((a, b) => b.count - a.count || a.phrase.length - b.phrase.length);

        const topPhrases = otherPhrases.slice(0, 9);

        const finalFilters = userPhraseObj ? [userPhraseObj, ...topPhrases] : topPhrases;

        return finalFilters.sort((a, b) => b.count - a.count || a.phrase.length - b.phrase.length);
    }, [activeResults, queryWords, searchType]);

    const displayedResults = useMemo(() => {
        let baseResults = activeResults;

        // Exact match applies to Text Mode only
        if (searchType === 'text' && exactMatch && isSingleWordSearch) {
            const normalizedQuery = queryWords.join(' ');
            const regex = new RegExp(`(^|\\s)${normalizedQuery}(\\s|$)`);
            baseResults = baseResults.filter(ayah => regex.test(normalizeArabicText(ayah.text)));
        }

        if (activePhraseFilter === 'all') {
            return baseResults;
        }

        return baseResults.filter(ayah => normalizeArabicText(ayah.text).includes(activePhraseFilter));
    }, [activeResults, queryWords, exactMatch, searchType, activePhraseFilter, isSingleWordSearch]);

    const occurrencesMap = useMemo(() => {
        if (searchType === 'number' || !query) return [];

        const transformedQuery = normalizeArabicText(correctedQuery || query).replace(/"/g, '');
        if (!transformedQuery) return [];

        const occurrences: { itemIndex: number; wordIndex: number; }[] = [];
        const searchTerms = transformedQuery.split(/\s+/);

        displayedResults.forEach((resultAyah, itemIndex) => {
            const ayahWords = normalizeArabicText(resultAyah.text).split(' ');

            for (let i = 0; i <= ayahWords.length - searchTerms.length; i++) {
                const slice = ayahWords.slice(i, i + searchTerms.length);
                if (slice.join(' ') === searchTerms.join(' ')) {
                    occurrences.push({ itemIndex, wordIndex: i });
                }
            }
        });
        return occurrences;
    }, [displayedResults, query, correctedQuery, searchType]);

    const totalOccurrences = occurrencesMap.length;

    const generalOccurrences = useMemo(() => {
        if (searchType === 'number' || queryWords.length === 0) return 0;
        let count = 0;
        activeResults.forEach(ayah => {
            const ayahText = normalizeArabicText(ayah.text);
            queryWords.forEach(word => {
                count += (ayahText.match(new RegExp(word, 'g')) || []).length;
            });
        });
        return count;
    }, [activeResults, queryWords, searchType]);

    const exactOccurrences = useMemo(() => {
        if (searchType === 'number' || queryWords.length === 0) return 0;
        let count = 0;
        const regex = new RegExp(`(^|\\s)(${queryWords.join('|')})(\\s|$)`, 'g');
        activeResults.forEach(ayah => {
            const ayahText = normalizeArabicText(ayah.text);
            count += (ayahText.match(regex) || []).length;
        });
        return count;
    }, [activeResults, queryWords, searchType]);

    const neighboringWords = useMemo(() => {
        if (searchType === 'number' || !isSingleWordSearch) return [];
        return findNeighboringWords(activeResults, correctedQuery || query);
    }, [activeResults, query, correctedQuery, searchType, isSingleWordSearch]);

    const handleShowMore = () => setVisibleSuggestionsCount(prev => prev + 7);

    const formatResultsForExport = useCallback((displayEditionData: any[]): string => {
        if (displayedResults.length === 0) return 'لم يتم العثور على نتائج.';

        const savedTemplate = localStorage.getItem(EXPORT_TEMPLATE_KEY);
        const isTextSearch = searchType === 'text';
        const queryToExport = correctedQuery || query;

        const defaultTemplateForNumber = `ملخص البحث عن الآيات رقم: "{{query}}"
- عدد الآيات التي تم العثور عليها: {{ayah_count}}

====================================

{{#results}}
"{{ayah_text}}" (سورة {{surah_name}} - الآية {{ayah_number_in_surah}})
---
{{/results}}
`;

        const defaultTemplate = isTextSearch ? DEFAULT_EXPORT_TEMPLATE : defaultTemplateForNumber;
        let template = savedTemplate || defaultTemplate;

        template = template.replace(/{{query}}/g, queryToExport);
        template = template.replace(/{{ayah_count}}/g, String(displayedResults.length));

        if (isTextSearch) {
            template = template.replace(/{{general_occurrences}}/g, String(generalOccurrences));
            template = template.replace(/{{exact_occurrences}}/g, String(exactOccurrences));
            template = template.replace(/{{exact_match_status}}/g, exactMatch ? 'مفعل' : 'غير مفعل');
        } else {
            template = template.replace(/-\\s*إجمالي التكرارات:.*?\\n/g, '');
            template = template.replace(/-\\s*المطابقات التامة:.*?\\n/g, '');
            template = template.replace(/-\\s*خيار التطابق:.*?\\n/g, '');
        }

        const resultsRegex = /{{#results}}(.*){{\/results}}/s;
        const match = template.match(resultsRegex);

        if (match && match[1]) {
            const itemTemplate = match[1];
            const allResultsString = displayedResults.map(resultAyah => {
                let itemString = itemTemplate;
                const displaySurah = displayEditionData.find(s => s.number === resultAyah.surah!.number);
                const displayAyah = displaySurah?.ayahs.find(a => a.numberInSurah === resultAyah.numberInSurah);
                const textToExport = displayAyah?.text || resultAyah.text || '';

                itemString = itemString.replace(/{{ayah_text}}/g, textToExport);
                itemString = itemString.replace(/{{surah_name}}/g, resultAyah.surah?.name || '');
                itemString = itemString.replace(/{{ayah_number_in_surah}}/g, String(resultAyah.numberInSurah));
                return itemString;
            }).join('');

            template = template.replace(resultsRegex, allResultsString);
        }

        return template.trim();
    }, [displayedResults, searchType, correctedQuery, query, generalOccurrences, exactOccurrences, exactMatch]);

    // Reset filters when query changes
    useEffect(() => {
        setActivePhraseFilter('all');
        setExactMatch(false);
        setVisibleSuggestionsCount(7);
    }, [query, correctedQuery]);

    return {
        exactMatch, setExactMatch,
        visibleSuggestionsCount, handleShowMore,
        activePhraseFilter, setActivePhraseFilter,
        queryWords, isSingleWordSearch,
        phraseFilters,
        displayedResults,
        occurrencesMap, totalOccurrences,
        generalOccurrences, exactOccurrences,
        neighboringWords,
        formatResultsForExport,
    };
};

import React, { useState } from 'react';
import type { Ayah } from '../../types';
import { SparklesIcon } from '../icons';

interface SearchResultsHeaderProps {
    searchType: 'text' | 'number';
    query: string;
    correctedQuery?: string;
    displayedResultsCount: number;
    resultsCount: number;
    isSingleWordSearch: boolean;
    generalOccurrences: number;
    exactOccurrences: number;
    exactMatch: boolean;
    setExactMatch: (value: boolean) => void;
    totalOccurrences: number;
    onJumpToOccurrence: (target: number) => void;
    cachedAnalysisExists: boolean;
    onNewSearch: (query: string) => void;
}

const SearchResultsHeader: React.FC<SearchResultsHeaderProps> = ({
    searchType, query, correctedQuery, displayedResultsCount, resultsCount,
    isSingleWordSearch, generalOccurrences, exactOccurrences, exactMatch,
    setExactMatch, totalOccurrences, onJumpToOccurrence, 
    cachedAnalysisExists, onNewSearch
}) => {
    const [jumpToValue, setJumpToValue] = useState('');

    const handleJump = () => {
        const target = parseInt(jumpToValue, 10);
        if (isNaN(target) || target < 1 || target > totalOccurrences) {
            alert(`الرجاء إدخال رقم صحيح بين 1 و ${totalOccurrences}`);
            return;
        }
        onJumpToOccurrence(target);
    };

    const finalQueryForChecks = correctedQuery || query;
    const shouldShowAnalysisButton = finalQueryForChecks.trim().split(/\s+/).filter(Boolean).length === 1 && searchType === 'text';

    return (
        <div className="mb-4 p-4 bg-surface-subtle rounded-lg border border-border-default">
            {correctedQuery && (
                <div className="mb-4 p-4 bg-blue-500/10 border-l-4 border-blue-500 text-text-secondary rounded-r-lg">
                    <p>لم نجد نتائج لـ "{query}". نعرض لك نتائج لأقرب كلمة: <strong>{correctedQuery}</strong>.</p>
                    <button onClick={() => onNewSearch(query)} className="mt-2 text-sm font-bold hover:underline">
                        ابحث عن "{query}" بدلاً من ذلك
                    </button>
                </div>
            )}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div className="flex-grow">
                    {searchType === 'text' ? (
                        <h3 className="text-lg font-semibold text-text-secondary">نتائج البحث عن الكلمات: <span className="font-bold text-primary-text-strong">{(correctedQuery || query).replace(/"/g, '')}</span></h3>
                    ) : (
                        <h3 className="text-lg font-semibold text-text-secondary">الآيات التي تحمل الرقم "<span className="font-bold text-primary-text-strong">{query}</span>"</h3>
                    )}

                    {resultsCount > 0 && (
                        <div className="flex items-center gap-2 mt-2 flex-wrap">
                            <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold bg-green-500/20 text-text-primary shadow-sm cursor-help" title="إجمالي عدد الآيات التي تحتوي على كلمة البحث.">{displayedResultsCount} آيات</span>
                            {searchType === 'text' && isSingleWordSearch && (
                              <>
                                <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold bg-blue-500/20 text-text-primary shadow-sm cursor-help" title="إجمالي عدد مرات ورود كلمة البحث في كل الآيات.">{generalOccurrences} تكراراً</span>

                                <button
                                    onClick={() => {
                                        setExactMatch(!exactMatch);
                                    }}
                                    className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold shadow-sm transition-all duration-200 cursor-pointer focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-surface-subtle focus:ring-purple-500
                                    ${exactMatch 
                                        ? 'bg-purple-600 text-white' 
                                        : 'bg-purple-500/20 text-text-primary hover:bg-purple-500/40'}`}
                                    title="تفعيل/إلغاء تفعيل المطابقة التامة"
                                    aria-pressed={exactMatch}
                                >
                                    {exactOccurrences} مطابقة
                                </button>
                              </>
                            )}
                        </div>
                    )}
                </div>
            </div>
            {searchType === 'text' && totalOccurrences > 1 && (
                <div className="mt-3 pt-3 border-t border-border-default flex items-center gap-2 flex-wrap">
                    <label htmlFor="jump-input" className="text-sm font-semibold text-text-muted">الانتقال إلى التكرار:</label>
                    <input id="jump-input" type="number" value={jumpToValue} onChange={(e) => setJumpToValue(e.target.value)} min="1" max={totalOccurrences} className="w-24 p-1.5 border border-border-default rounded-md text-center bg-surface focus:outline-none focus:ring-2 focus:ring-primary" placeholder={`1 - ${totalOccurrences}`} />
                    <button onClick={handleJump} className="px-4 py-1.5 bg-primary text-white text-sm font-semibold rounded-md hover:bg-primary-hover transition-colors">اذهب</button>
                </div>
            )}
            {cachedAnalysisExists && shouldShowAnalysisButton && (
                <div className="mt-3 pt-3 border-t border-border-default">
                    <a href={`#/analysis/${encodeURIComponent(finalQueryForChecks)}`} onClick={(e) => { e.preventDefault(); window.location.hash = `#/analysis/${encodeURIComponent(finalQueryForChecks)}`; }} className="inline-flex items-center gap-2 px-4 py-2 bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 font-semibold rounded-md hover:bg-blue-200 dark:hover:bg-blue-800/60 transition-colors">
                        <SparklesIcon className="w-5 h-5" />
                        <span>عرض التحليل المحفوظ لهذه الكلمة</span>
                    </a>
                </div>
            )}
        </div>
    );
};

export default SearchResultsHeader;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import type { Ayah, SurahData, QuranEdition, SavedAyahItem, SavedSearchItem, FontSize, FontStyleType } from '../types';
import { SearchIcon, ClearIcon, BackspaceIcon, BackspaceReverseIcon } from './icons';
import { normalizeArabicText, formatSurahNameForDisplay } from '../utils/text';
import { useSearchLogic } from '../hooks/useSearchLogic';
import { db } from '../firebase';

import DiscussionSection from './DiscussionSection';
import AyahActionPopover from './AyahActionPopover';
import SearchResultItem from './SearchResultItem';
import SearchResultsHeader from './search/SearchResultsHeader';
import SearchResultsToolbar from './search/SearchResultsToolbar';
import PhraseFilters from './search/PhraseFilters';
import NeighboringWords from './search/NeighboringWords';


interface SearchViewProps {
  query: string;
  results: Ayah[];
  onNewSearch: (word: string, sourceEdition?: string, position?: { surah: number, ayah: number, wordIndex: number }) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  onSearchComplete: () => void;
  autoOpenDiscussion?: boolean;
  displayEdition: QuranEdition;
  displayEditionData: SurahData[];
  searchEdition: string;
  fontSize: FontSize;
  fontStyle: FontStyleType;
  position?: { surah: number, ayah: number, wordIndex: number };
  simpleCleanData: SurahData[];
  onSaveAyah: (item: SavedAyahItem) => void;
  onSaveSearch: (item: SavedSearchItem) => void;
  searchType?: 'text' | 'number';
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  correctedQuery?: string;
}

export const SearchView: React.FC<SearchViewProps> = ({ 
    query, results, onNewSearch, onSearchByAyahNumber, onSearchComplete, autoOpenDiscussion, 
    displayEdition, displayEditionData, searchEdition, fontSize, fontStyle, position, 
    simpleCleanData, onSaveAyah, onSaveSearch, searchType = 'text',
    currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
    allAudioEditions, selectedAudioEdition, onAudioEditionChange,
    correctedQuery
}) => {
  const [editableQuery, setEditableQuery] = useState(query);
  const [isAllCopied, setIsAllCopied] = useState(false);

  const itemRefs = useRef<React.RefObject<HTMLLIElement>[]>([]);

  const [wordPopoverState, setWordPopoverState] = useState<{
    resultIndex: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [cachedAnalysisExists, setCachedAnalysisExists] = useState(false);
  const [pulsingWord, setPulsingWord] = useState<{ itemIndex: number; wordIndex: number } | null>(null);

  const {
    exactMatch, setExactMatch,
    visibleSuggestionsCount, handleShowMore,
    activePhraseFilter, setActivePhraseFilter,
    queryWords, isSingleWordSearch,
    phraseFilters,
    displayedResults,
    occurrencesMap, totalOccurrences,
    generalOccurrences, exactOccurrences,
    neighboringWords,
    formatResultsForExport,
  } = useSearchLogic(query, correctedQuery, results, searchType as 'text' | 'number', simpleCleanData);


  const normalizedQueryForDiscussion = useMemo(() => {
    if (searchType === 'number') return `topic:ayah-number:${query}`;
    return normalizeArabicText(correctedQuery || query);
  }, [query, correctedQuery, searchType]);

  useEffect(() => { setEditableQuery(query); }, [query]);
  useEffect(() => { onSearchComplete(); }, [results, onSearchComplete]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(event.target as Node)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
        if (!(event.target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  useEffect(() => {
    const checkAnalysisCache = async () => {
        const trimmedQuery = (correctedQuery || query).trim();
        const isSingleWord = trimmedQuery.split(/\s+/).length === 1 && trimmedQuery.length > 1;
        if (isSingleWord && searchType === 'text') {
            setCachedAnalysisExists(false);
            try {
                const snapshot = await db.collection('qran_word_analysis_cache').doc(normalizeArabicText(trimmedQuery)).collection('analyses').limit(1).get();
                if (!snapshot.empty) setCachedAnalysisExists(true);
            } catch (error) { console.error("Error checking analysis cache:", error); }
        } else {
            setCachedAnalysisExists(false);
        }
    };
    checkAnalysisCache();
  }, [query, correctedQuery, searchType]);

  itemRefs.current = displayedResults.map((_, i) => itemRefs.current[i] ?? React.createRef());

  useEffect(() => {
    if (currentlyPlayingAyahGlobalNumber) {
        const playingIndex = displayedResults.findIndex(ayah => ayah.number === currentlyPlayingAyahGlobalNumber);
        if (playingIndex !== -1 && itemRefs.current[playingIndex]?.current) {
            itemRefs.current[playingIndex].current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }
  }, [currentlyPlayingAyahGlobalNumber, displayedResults]);

  const handleJumpToOccurrence = (target: number) => {
    const occurrence = occurrencesMap[target - 1];
    if (occurrence && itemRefs.current[occurrence.itemIndex]?.current) {
        const element = itemRefs.current[occurrence.itemIndex].current;
        element?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        setPulsingWord({ itemIndex: occurrence.itemIndex, wordIndex: occurrence.wordIndex });
        setTimeout(() => setPulsingWord(null), 3000);
    }
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedQuery = editableQuery.trim();
    if (trimmedQuery && trimmedQuery !== query) onNewSearch(trimmedQuery);
  };

  const handleDeleteFirstChar = () => {
    const newQuery = editableQuery.slice(1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleDeleteLastChar = () => {
    const newQuery = editableQuery.slice(0, -1);
    if (newQuery) onNewSearch(newQuery); else setEditableQuery('');
  };

  const handleSaveSearch = () => {
    const queryToSave = correctedQuery || query;
    if (queryToSave) onSaveSearch({ type: 'search', id: queryToSave, query: queryToSave, createdAt: Date.now() });
  };

  const handleCopyAll = () => {
    const textToCopy = formatResultsForExport(displayEditionData);
    if (textToCopy) navigator.clipboard.writeText(textToCopy).then(() => {
        setIsAllCopied(true);
        setTimeout(() => setIsAllCopied(false), 2500);
    });
  };

  const handleDownloadAll = () => {
    const textToDownload = formatResultsForExport(displayEditionData);
    if (textToDownload) {
        const blob = new Blob([textToDownload], { type: 'text/plain;charset=utf-8' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        const safeQuery = (correctedQuery || query).replace(/[^a-zA-Z0-9-ء-ي ]/g, "").trim() || 'results';
        link.download = `qran-top-search-${safeQuery}.txt`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(link.href);
    }
  };

  const handlePlayAll = () => {
    if (displayedResults.length > 0) onStartPlayback(displayedResults, selectedAudioEdition);
  };

  // --- Ayah Action Handlers ---
  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({ type: 'ayah', id: `${ayah.surah!.number}:${ayah.numberInSurah}`, surah: ayah.surah!.number, ayah: ayah.numberInSurah, text: ayah.text || '', createdAt: Date.now() });
    setActivePopover(null);
  };
  const handleCopyAyah = (ayah: Ayah) => {
    const isImlaei = fontStyle === 'imlai_1' || fontStyle === 'imlai_2';
    let ayahText = ayah.text || '';

    if (isImlaei) {
        const marksToRemoveRegex = /[\u06D6-\u06ED]/g;
        ayahText = ayahText.replace(marksToRemoveRegex, '');
    }

    const textToCopy = `"${ayahText}" (سورة ${formatSurahNameForDisplay(ayah.surah?.name)} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };
  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah!.number);
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    if (simpleAyah?.text) onNewSearch(simpleAyah.text, 'quran-simple-clean', { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    else if (ayah.text) onNewSearch(ayah.text, displayEdition.identifier, { surah: ayah.surah!.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    setActivePopover(null);
  };
  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = results.findIndex(a => a.number === ayah.number);
    if (startIndex !== -1) onStartPlayback(results, selectedAudioEdition, startIndex);
    setActivePopover(null);
  };

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {searchType !== 'number' && (
          <div className="mb-6">
              <form onSubmit={handleFormSubmit} className="flex-grow w-full flex items-center gap-2">
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteFirstChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من بداية الكلمة"><BackspaceIcon className="w-5 h-5" /></button>}
                <div className="relative flex-grow">
                    <input type="text" value={editableQuery} onChange={(e) => setEditableQuery(e.target.value)} placeholder="ابحث عن كلمة..." className="w-full text-xl font-bold text-primary-text-strong border-b-2 border-border-default focus:border-primary bg-transparent py-2 pr-4 pl-12 outline-none transition-colors" aria-label="كلمة البحث"/>
                    {editableQuery && (<button type="button" onClick={() => { setEditableQuery(''); onNewSearch(''); }} className="absolute left-1 top-1/2 -translate-y-1/2 p-2 text-text-muted hover:text-text-primary rounded-full" aria-label="مسح البحث"><ClearIcon className="w-5 h-5" /></button>)}
                </div>
                {isSingleWordSearch && editableQuery.length > 1 && <button type="button" onClick={handleDeleteLastChar} className="flex-shrink-0 p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors" title="حذف من نهاية الكلمة"><BackspaceReverseIcon className="w-5 h-5" /></button>}
                <button type="submit" className="flex-shrink-0 p-3 bg-primary text-white rounded-full hover:bg-primary-hover transition-colors focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50" aria-label="بحث"><SearchIcon className="w-5 h-5" /></button>
            </form>
            <NeighboringWords neighboringWords={neighboringWords} visibleSuggestionsCount={visibleSuggestionsCount} onNeighborClick={(word) => onNewSearch(`${editableQuery.trim()} ${word}`)} onShowMore={handleShowMore}/>
          </div>
      )}

      <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
        <PhraseFilters phraseFilters={phraseFilters} activePhraseFilter={activePhraseFilter} setActivePhraseFilter={setActivePhraseFilter} resultsCount={displayedResults.length}/>
        <SearchResultsHeader 
            searchType={searchType} query={query} correctedQuery={correctedQuery}
            displayedResultsCount={displayedResults.length} resultsCount={results.length}
            isSingleWordSearch={isSingleWordSearch} generalOccurrences={generalOccurrences}
            exactOccurrences={exactOccurrences} exactMatch={exactMatch} setExactMatch={setExactMatch}
            totalOccurrences={totalOccurrences} onJumpToOccurrence={handleJumpToOccurrence}
            cachedAnalysisExists={cachedAnalysisExists} onNewSearch={onNewSearch}
        />

        {displayedResults.length > 0 && (
          <>
            <SearchResultsToolbar
                isPlaybackLoading={isPlaybackLoading} allAudioEditions={allAudioEditions}
                onPlayAll={handlePlayAll} selectedAudioEdition={selectedAudioEdition}
                onAudioEditionChange={onAudioEditionChange} searchType={searchType}
                onSaveSearch={handleSaveSearch} onCopyAll={handleCopyAll}
                isAllCopied={isAllCopied} onDownloadAll={handleDownloadAll}
            />
            <DiscussionSection topicId={normalizedQueryForDiscussion} wordForTopic={correctedQuery || query} autoOpen={autoOpenDiscussion} showAnalysisButton={isSingleWordSearch} onAnalysisClick={() => window.location.hash = `#/analysis/${encodeURIComponent(correctedQuery || query)}`}/>
          </>
        )}

        <div className="mt-6">
            {displayedResults.length > 0 ? (
                <ul className="space-y-4">
                    {displayedResults.map((ayah, index) => {
                        const simpleSurah = simpleCleanData.find(s => s.number === ayah.surah?.number);
                        const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
                        return (
                           <SearchResultItem 
                                key={ayah.number} itemRef={itemRefs.current[index]} ayah={ayah} 
                                queryWords={searchType === 'number' ? [] : queryWords} onNewSearch={onNewSearch}
                                displayEdition={displayEdition} displayEditionData={displayEditionData} searchEdition={searchEdition}
                                fontSize={fontSize} fontStyle={fontStyle} searchType={searchType} isCurrentlyPlaying={ayah.number === currentlyPlayingAyahGlobalNumber}
                                pulsingWordIndex={pulsingWord?.itemIndex === index ? pulsingWord.wordIndex : -1} resultIndex={index}
                                simpleAyahText={simpleAyah?.text || ''}
                                onUthmaniWordClick={(e, idx, text) => { if (wordPopoverState?.resultIndex === idx) setWordPopoverState(null); else setWordPopoverState({ resultIndex: idx, simpleText: text, triggerElement: e.currentTarget }); }}
                                onOpenPopover={(ayah, triggerElement) => setActivePopover({ ayah, triggerElement })}
                            />
                       );
                    })}
                </ul>
            ) : (<div className="text-center p-10 text-lg text-text-muted">لم يتم العثور على نتائج.</div>)}
        </div>
      </main>

       {wordPopoverState && (
         <div ref={wordPopoverRef} className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return { top: `${rect.bottom + window.scrollY + 5}px`, left: `${rect.left + window.scrollX + rect.width / 2}px`, transform: 'translateX(-50%)' };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, wordIndex) => {
                const originalAyah = displayedResults[wordPopoverState.resultIndex];
                return (
                    <button key={wordIndex} onClick={() => { onNewSearch(word, 'quran-simple-clean', { surah: originalAyah.surah!.number, ayah: originalAyah.numberInSurah, wordIndex: wordIndex }); setWordPopoverState(null); }} className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors">
                        {word}
                    </button>
                );
            })}
        </div>
      )}

       {activePopover && <AyahActionPopover activePopover={activePopover} onClose={() => setActivePopover(null)} onSave={handleSaveClick} onCopy={handleCopyAyah} onSearchText={handleSearchByAyahText} onSearchNumber={onSearchByAyahNumber} onPlayFrom={handlePlayFromAyah} copiedAyah={copiedAyah} />}
    </div>
  );
};

import React from 'react';
import type { Ayah, SurahData, Collections, QuranEdition, SavedItem, FontSize, BrowsingMode, FontStyleType } from '../types';

import HomeView from './HomeView';
import SurahDetailView from './SurahDetailView';
import { SearchView } from './SearchView';
import SettingsView from './SettingsView';
import SavedView from './SavedView';
import KhatmiyahView from './KhatmiyahView';
import AudioKhatmiyahView from './AudioKhatmiyahView';
import AdminView from './AdminView';
import CommentsCloudView from './CommentsCloudView';
import WordAnalysisView from './WordAnalysisView';
import PrivacyPolicyView from './PrivacyPolicyView';
import LoadingScreen from './LoadingScreen';
import AboutView from './AboutView';

import { QURAN_INDEX } from '../quranIndex';
import { JUZ_INDEX, HIZB_INDEX } from '../quranPartitions';

interface AppRouterProps {
    pathParts: string[];
    queryParams: URLSearchParams;
    isInitialLoading: boolean;
    quranData: SurahData[] | undefined;
    simpleSearchableAyahs: Ayah[];
    collections: Collections;
    audioKhatmiyahProgress: { ayahNumber: number } | null;
    handleSaveAudioKhatmiyahProgress: (ayahNumber: number) => void;
    ALL_AUDIO_EDITIONS: QuranEdition[];
    selectedAudioEdition: string;
    setSelectedAudioEdition: (id: string) => void;
    allQuranData: { [key: string]: SurahData[] } | null;
    fetchCustomEditionData: (id: string) => void;
    fontSize: FontSize;
    setFontSize: (size: FontSize) => void;
    fontStyle: FontStyleType;
    activeEditions: QuranEdition[];
    selectedEdition: string;
    setSelectedEdition: (id: string) => void;
    handleDeleteCollection: (id: string) => void;
    handleDeleteSavedItem: (collectionId: string, itemId: string) => void;
    updateItemNotes: (collectionId: string, itemId: string, notes: string) => void;
    handleExportNotebook: () => Promise<string>;
    handleImportNotebook: (code: string) => Promise<void>;
    handleSearch: (query: string, sourceEdition?: string, position?: { surah: number; ayah: number; wordIndex: number; }) => void;
    displayEdition: QuranEdition;
    browsingMode: BrowsingMode;
    handleSaveItem: (item: SavedItem) => void;
    handleSearchByAyahNumber: (num: number) => void;
    currentlyPlayingAyahGlobalNumber: number | null;
    playbackInfo: any;
    handleStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
    hizbQuarterStartMap: Map<number, number>;
    setIsSearching: (isSearching: boolean) => void;
    performSearchByAyahNumber: (num: number) => Ayah[];
    performSearch: (query: string) => { results: Ayah[], finalSearchEdition: string, correctedQuery?: string };
}

const AppRouter: React.FC<AppRouterProps> = (props) => {
    const {
        pathParts, queryParams, isInitialLoading, quranData, simpleSearchableAyahs, collections,
        audioKhatmiyahProgress, handleSaveAudioKhatmiyahProgress, ALL_AUDIO_EDITIONS,
        selectedAudioEdition, setSelectedAudioEdition, allQuranData, fetchCustomEditionData,
        fontSize, setFontSize, fontStyle, activeEditions, selectedEdition, setSelectedEdition,
        handleDeleteCollection, handleDeleteSavedItem, updateItemNotes, handleExportNotebook,
        handleImportNotebook, handleSearch, displayEdition, browsingMode, handleSaveItem,
        handleSearchByAyahNumber, currentlyPlayingAyahGlobalNumber, playbackInfo, handleStartPlayback,
        hizbQuarterStartMap, setIsSearching, performSearchByAyahNumber, performSearch
    } = props;

    if (isInitialLoading) return <LoadingScreen />;
    if (pathParts[0] === 'admin') return <AdminView />;
    if (pathParts[0] === 'khatmiyah') return <KhatmiyahView khatmiyahId={pathParts[1] || null} />;
    if (pathParts[0] === 'audio-khatmiyah') {
        return <AudioKhatmiyahView
            allAyahs={simpleSearchableAyahs}
            allAudioEditions={ALL_AUDIO_EDITIONS}
            initialAyahNumber={audioKhatmiyahProgress?.ayahNumber || 1}
            onSaveProgress={handleSaveAudioKhatmiyahProgress}
            selectedAudioEdition={selectedAudioEdition}
            onAudioEditionChange={setSelectedAudioEdition}
            allQuranData={allQuranData}
            fetchCustomEditionData={fetchCustomEditionData}
            activeEditions={activeEditions}
        />;
    }
    if (pathParts[0] === 'saved') return <SavedView collections={collections} collectionId={pathParts[1] || null} onDeleteCollection={handleDeleteCollection} onDeleteSavedItem={handleDeleteSavedItem} onUpdateNotes={updateItemNotes} />;
    if (pathParts[0] === 'analysis') return <WordAnalysisView simpleCleanData={allQuranData?.['quran-simple-clean'] || []} initialWord={pathParts[1] ? decodeURIComponent(pathParts[1]) : undefined} />;
    if (pathParts[0] === 'settings') return <SettingsView 
        onExportNotebook={handleExportNotebook} 
        onImportNotebook={handleImportNotebook}
    />;
    if (pathParts[0] === 'about') return <AboutView />;
    if (pathParts[0] === 'privacy-policy') return <PrivacyPolicyView />;

    // Handle Page Route
    if (pathParts[0] === 'page' && pathParts[1]) {
        if (isInitialLoading || !quranData) {
            return null;
        }
        const pageNumber = parseInt(pathParts[1], 10);

        // Collect ALL Surahs that have ayahs on this page
        const pageSurahs: SurahData[] = [];
        let startAyahInFirstSurah: number | null = null;

        for (const surah of quranData) {
            const ayahsOnPage = surah.ayahs.filter(a => a.page === pageNumber);
            if (ayahsOnPage.length > 0) {
                // We create a "Partial Surah" object containing only the ayahs for this page
                pageSurahs.push({
                    ...surah,
                    ayahs: ayahsOnPage
                });

                if (startAyahInFirstSurah === null) {
                    startAyahInFirstSurah = ayahsOnPage[0].numberInSurah;
                }
            }
        }

        if (pageSurahs.length > 0) {
            // We pass the first surah as the 'main' surah prop for context, 
            // but we pass the array of pageSurahs for the actual rendering.
            return <SurahDetailView 
                surah={pageSurahs[0]}
                pageSurahs={pageSurahs} // Pass the collected surahs
                highlightAyahNumber={startAyahInFirstSurah}
                onWordClick={handleSearch}
                displayEdition={displayEdition}
                fontSize={fontSize}
                fontStyle={fontStyle}
                browsingMode={'page'} // Force page mode
                onSaveAyah={handleSaveItem}
                onSearchByAyahNumber={handleSearchByAyahNumber}
                currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                onStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                selectedAudioEdition={selectedAudioEdition}
                simpleCleanData={allQuranData?.['quran-simple-clean'] || []}
                hizbQuarterStartMap={hizbQuarterStartMap}
                forcedPageNumber={pageNumber} // Explicitly pass the page number
            />;
        } else {
             return <div className="text-center p-10">الصفحة غير موجودة</div>;
        }
    }

    if (pathParts[0] === 'surah' && pathParts[1]) {
        if (isInitialLoading || !quranData) {
            return null;
        }
        const surahNumber = parseInt(pathParts[1], 10);
        const highlightAyahNumber = queryParams.get('ayah') ? parseInt(queryParams.get('ayah')!, 10) : null;
        const surah = quranData.find(s => s.number === surahNumber);
        if (surah) {
            return <SurahDetailView 
                surah={surah}
                highlightAyahNumber={highlightAyahNumber}
                onWordClick={handleSearch}
                displayEdition={displayEdition}
                fontSize={fontSize}
                browsingMode={browsingMode}
                fontStyle={fontStyle}
                onSaveAyah={handleSaveItem}
                onSearchByAyahNumber={handleSearchByAyahNumber}
                currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                onStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                selectedAudioEdition={selectedAudioEdition}
                simpleCleanData={allQuranData?.['quran-simple-clean'] || []}
                hizbQuarterStartMap={hizbQuarterStartMap}
            />;
        }
    }
    if (pathParts[0] === 'search') {
        const commonProps = {
            onNewSearch: handleSearch, onSearchByAyahNumber: handleSearchByAyahNumber,
            onSearchComplete: () => setIsSearching(false), displayEdition: displayEdition,
            displayEditionData: quranData || [], 
            fontSize: fontSize, fontStyle: fontStyle, simpleCleanData: allQuranData?.['quran-simple-clean'] || [],
            onSaveAyah: handleSaveItem, onSaveSearch: handleSaveItem,
            currentlyPlayingAyahGlobalNumber: currentlyPlayingAyahGlobalNumber, isPlaybackLoading: !!playbackInfo?.trigger,
            onStartPlayback: handleStartPlayback, allAudioEditions: ALL_AUDIO_EDITIONS,
            selectedAudioEdition: selectedAudioEdition, onAudioEditionChange: setSelectedAudioEdition,
        };
        if (pathParts[1] === 'number' && pathParts[2]) {
            const ayahNumber = parseInt(pathParts[2], 10);
            return <SearchView {...commonProps} query={pathParts[2]} results={performSearchByAyahNumber(ayahNumber)} searchEdition={'quran-simple-clean'} searchType="number" />;
        }
        const query = pathParts[1] ? decodeURIComponent(pathParts[1]) : "";
        const searchResult = performSearch(query);
        const position = queryParams.get('s') ? { surah: parseInt(queryParams.get('s')!), ayah: parseInt(queryParams.get('a')!), wordIndex: parseInt(queryParams.get('w')!) } : undefined;
        return <SearchView {...commonProps} query={query} results={searchResult.results} correctedQuery={searchResult.correctedQuery} autoOpenDiscussion={!!queryParams.get('from')} searchEdition={searchResult.finalSearchEdition} position={position} />;
    }
    if (pathParts[0] === 'comments') return <CommentsCloudView />;

    return <HomeView surahList={QURAN_INDEX} juzList={JUZ_INDEX} hizbList={HIZB_INDEX} />;
};

export default AppRouter;

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { SurahData, Ayah, SavedItem, FontStyleType } from './types';
import { useQuranData } from './hooks/useQuranData';
import { useSettings } from './hooks/useSettings';
import { useRouting } from './hooks/useRouting';
import { useAudioPlayer } from './hooks/useAudioPlayer';
import { useNotebook } from './hooks/useNotebook';
import { AuthProvider } from './hooks/useAuth';
import { useSearch } from './hooks/useSearch';
import { useServiceWorkerUpdater } from './hooks/useServiceWorkerUpdater';
import AppRouter from './components/AppRouter';
import TopProgressBar from './components/TopProgressBar';
import SidePanel from './components/SidePanel';
import AudioPlayerBar from './components/AudioPlayerBar';
import Toolbox from './components/Toolbox';
import SaveItemModal from './components/SaveItemModal';
import UpdateNotification from './components/UpdateNotification';
import { ArrowUpIcon, RefreshIcon, WifiOffIcon } from './components/icons';
import Header from './components/Header';


const KHATMIYAH_AUDIO_PROGRESS_KEY = 'qran_khatmiyah_audio_progress';


const App: React.FC = () => {
    // --- State from Hooks ---
    const {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions,
        fetchCustomEditionData, dataSourceStatus, error: dataError
    } = useQuranData();

    const { currentPath, pathParts, queryParams } = useRouting();

    const {
        fontSize, setFontSize,
        fontStyle, setFontStyle,
        browsingMode, setBrowsingMode, activeEditions, selectedEdition,
        setSelectedEdition, selectedAudioEdition, setSelectedAudioEdition,
        displayEdition
    } = useSettings();

    const { 
        simpleSearchableAyahs, 
        tryParseAyahReference, 
        performSearch, 
        performSearchByAyahNumber 
    } = useSearch(allQuranData);

    const {
        playbackInfo, currentlyPlayingAyahGlobalNumber, selectedAudioEditionDetails,
        handleStartPlayback, handlePlayPause, handleNext, handlePrev, handleClosePlayback, ALL_AUDIO_EDITIONS
    } = useAudioPlayer(currentPath, allQuranData, selectedAudioEdition, setSelectedAudioEdition, fetchCustomEditionData);

    const {
        collections, itemToSave, setItemToSave, handleSaveItem, handleConfirmSave,
        handleDeleteCollection, handleDeleteSavedItem, handleExportNotebook,
        handleImportNotebook, updateItemNotes,
    } = useNotebook();

    const { showUpdateNotification, handleUpdate } = useServiceWorkerUpdater();

    // --- App-level State ---
    const [isSearching, setIsSearching] = useState<boolean>(false);
    const [showScroll, setShowScroll] = useState(false);
    const [isSidePanelOpen, setIsSidePanelOpen] = useState(false);

    const [audioKhatmiyahProgress, setAudioKhatmiyahProgress] = useState<{ ayahNumber: number } | null>(() => {
        try {
            const stored = localStorage.getItem(KHATMIYAH_AUDIO_PROGRESS_KEY);
            if (stored) return JSON.parse(stored);
        } catch (e) { console.error("Failed to parse audio khatmiyah progress", e); }
        return { ayahNumber: 1 };
    });

    const handleSaveAudioKhatmiyahProgress = useCallback((ayahNumber: number) => {
        const newProgress = { ayahNumber };
        setAudioKhatmiyahProgress(newProgress);
        localStorage.setItem(KHATMIYAH_AUDIO_PROGRESS_KEY, JSON.stringify(newProgress));
    }, []);

    // --- UI Effects ---
    useEffect(() => {
        const checkScrollTop = () => setShowScroll(window.pageYOffset > 400);
        window.addEventListener('scroll', checkScrollTop);
        return () => window.removeEventListener('scroll', checkScrollTop);
    }, []);

    useEffect(() => {
        if (!isInitialLoading) {
            const loader = document.querySelector('.static-loader');
            if (loader) {
                (loader as HTMLElement).style.opacity = '0';
                setTimeout(() => loader.remove(), 500);
            }
        }
    }, [isInitialLoading]);

    // --- Search Handlers ---
    const handleSearch = (query: string, sourceEdition?: string, position?: { surah: number; ayah: number; wordIndex: number; }) => {
        const ayahRef = tryParseAyahReference(query);
        if (ayahRef && !position) {
            window.location.hash = `#/surah/${ayahRef.surah}?ayah=${ayahRef.ayah}`;
            return;
        }
        setIsSearching(true);
        let url = `#/search/${encodeURIComponent(query)}?search_edition=${sourceEdition || 'quran-simple-clean'}`;
        if (position) url += `&s=${position.surah}&a=${position.ayah}&w=${position.wordIndex}`;
        window.location.hash = url;
    };

    const handleSearchByAyahNumber = (ayahNumber: number) => {
        setIsSearching(true);
        window.location.hash = `#/search/number/${ayahNumber}`;
    };


    // --- Other Handlers ---
    const scrollToTop = () => window.scrollTo({ top: 0, behavior: 'smooth' });

    // --- Data Derivations for Views ---
    const quranData = useMemo(() => allQuranData?.[selectedEdition], [allQuranData, selectedEdition]);

    const hizbQuarterStartMap = useMemo(() => {
        if (!simpleSearchableAyahs) return new Map<number, number>();
        const map = new Map<number, number>();
        simpleSearchableAyahs.forEach(ayah => {
            if (ayah.hizbQuarter && !map.has(ayah.hizbQuarter)) {
                map.set(ayah.hizbQuarter, ayah.number);
            }
        });
        return map;
    }, [simpleSearchableAyahs]);

    const isAudioKhatmiyahPage = currentPath.startsWith('#/audio-khatmiyah');
    const isPageWithToolbox = useMemo(() => 
        (currentPath.startsWith('#/surah/') || currentPath.startsWith('#/search/') || currentPath.startsWith('#/page/')) && !isAudioKhatmiyahPage, 
    [currentPath, isAudioKhatmiyahPage]);

    const isSearchDataReady = simpleSearchableAyahs.length > 0;

    // --- Retry Handler ---
    const handleRetryLoading = () => {
        window.location.reload();
    };

    if (dataError && !isSearchDataReady) {
        return (
            <div className="flex flex-col items-center justify-center min-h-screen bg-background text-text-primary p-6 text-center animate-fade-in">
                <WifiOffIcon className="w-20 h-20 text-text-muted mb-4 opacity-50" />
                <h2 className="text-2xl font-bold mb-2">تعذر تحميل البيانات</h2>
                <p className="text-text-secondary mb-6 max-w-md">
                    يبدو أن هناك مشكلة في الاتصال بالإنترنت. التطبيق يحتاج لتحميل البيانات الأساسية لأول مرة.
                </p>
                <button 
                    onClick={handleRetryLoading}
                    className="flex items-center gap-2 px-6 py-3 bg-primary text-white rounded-full hover:bg-primary-hover transition-colors shadow-lg"
                >
                    <RefreshIcon className="w-5 h-5" />
                    <span>إعادة المحاولة</span>
                </button>
            </div>
        );
    }

    return (
        <AuthProvider>
            <div className="bg-background text-text-primary min-h-screen transition-colors duration-300">
                <TopProgressBar isSearching={isSearching || isBackgroundLoading || loadingEditions.length > 0} />
                <SidePanel 
                    isOpen={isSidePanelOpen}
                    onClose={() => setIsSidePanelOpen(false)}
                    currentPath={currentPath}
                    onNavigate={(path) => {
                        const currentHash = window.location.hash || '#/';
                        if (currentHash !== path) {
                            window.location.hash = path;
                        }
                        setIsSidePanelOpen(false);
                    }}
                />
                {!isAudioKhatmiyahPage && (
                    <Header
                        setIsSidePanelOpen={setIsSidePanelOpen}
                        currentPath={currentPath}
                        dataSourceStatus={dataSourceStatus}
                        onSearch={handleSearch}
                        searchDisabled={isInitialLoading || !isSearchDataReady}
                        selectedEdition={selectedEdition}
                        setSelectedEdition={setSelectedEdition}
                        fontStyle={fontStyle}
                        setFontStyle={setFontStyle}
                        browsingMode={browsingMode}
                        setBrowsingMode={setBrowsingMode}
                        loadingEditions={loadingEditions}
                        onStartPlayback={handleStartPlayback}
                        isPlaybackLoading={!!playbackInfo?.trigger}
                        selectedAudioEdition={selectedAudioEdition}
                    />
                )}
                <main className={`pt-8 pb-24 ${isAudioKhatmiyahPage ? 'pt-0' : ''}`}>
                    <AppRouter
                        pathParts={pathParts}
                        queryParams={queryParams}
                        isInitialLoading={isInitialLoading}
                        quranData={quranData}
                        simpleSearchableAyahs={simpleSearchableAyahs}
                        collections={collections}
                        audioKhatmiyahProgress={audioKhatmiyahProgress}
                        handleSaveAudioKhatmiyahProgress={handleSaveAudioKhatmiyahProgress}
                        ALL_AUDIO_EDITIONS={ALL_AUDIO_EDITIONS}
                        selectedAudioEdition={selectedAudioEdition}
                        setSelectedAudioEdition={setSelectedAudioEdition}
                        allQuranData={allQuranData}
                        fetchCustomEditionData={fetchCustomEditionData}
                        fontSize={fontSize}
                        setFontSize={setFontSize}
                        fontStyle={fontStyle}
                        activeEditions={activeEditions}
                        selectedEdition={selectedEdition}
                        setSelectedEdition={setSelectedEdition}
                        handleDeleteCollection={handleDeleteCollection}
                        handleDeleteSavedItem={handleDeleteSavedItem}
                        updateItemNotes={updateItemNotes}
                        handleExportNotebook={handleExportNotebook}
                        handleImportNotebook={handleImportNotebook}
                        handleSearch={handleSearch}
                        displayEdition={displayEdition}
                        browsingMode={browsingMode}
                        handleSaveItem={handleSaveItem as (item: SavedItem) => void}
                        handleSearchByAyahNumber={handleSearchByAyahNumber}
                        currentlyPlayingAyahGlobalNumber={currentlyPlayingAyahGlobalNumber}
                        playbackInfo={playbackInfo}
                        handleStartPlayback={handleStartPlayback as (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void}
                        hizbQuarterStartMap={hizbQuarterStartMap}
                        setIsSearching={setIsSearching}
                        performSearchByAyahNumber={performSearchByAyahNumber}
                        performSearch={performSearch}
                    />
                </main>

                {isPageWithToolbox && <Toolbox
                    fontSize={fontSize} onFontSizeChange={setFontSize}
                    isAudioPlayerVisible={!!playbackInfo}
                    browsingMode={browsingMode} onBrowsingModeChange={setBrowsingMode}
                />}
                {itemToSave && <SaveItemModal item={itemToSave} collections={collections} onClose={() => setItemToSave(null)} onSave={handleConfirmSave} />}
                {playbackInfo && !isAudioKhatmiyahPage && <AudioPlayerBar 
                    playlist={playbackInfo.playlist} currentIndex={playbackInfo.currentIndex}
                    isPlaying={playbackInfo.isPlaying} isLoading={!!playbackInfo?.trigger}
                    onPlayPause={handlePlayPause} onNext={handleNext} onPrev={handlePrev}
                    onEnded={handleNext} onClose={handleClosePlayback}
                    audioEdition={selectedAudioEditionDetails}
                />}
                {showScroll && !isAudioKhatmiyahPage && <button onClick={scrollToTop} className={`fixed left-8 p-4 bg-primary text-white rounded-full shadow-lg hover:bg-primary-hover transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-opacity-50 ${!!playbackInfo ? 'bottom-28' : 'bottom-8'}`} aria-label="الانتقال إلى الأعلى"><ArrowUpIcon className="w-6 h-6" /></button>}
                {showUpdateNotification && <UpdateNotification onUpdate={handleUpdate} />}
            </div>
        </AuthProvider>
    );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import type { FontSize, BrowsingMode } from '../types';
import { ArrowLeftIcon, ArrowRightIcon, HomeIcon, PlusIcon, MinusIcon, DocumentDuplicateIcon, QueueListIcon } from './icons';

interface ToolboxProps {
    // Font Size
    fontSize: FontSize;
    onFontSizeChange: (size: FontSize) => void;
    isAudioPlayerVisible: boolean;
    // Browsing Mode
    browsingMode: BrowsingMode;
    onBrowsingModeChange: (mode: BrowsingMode) => void;
}

const FONT_SIZES: FontSize[] = ['xs', 'sm', 'md', 'lg', 'xl', 'xxl'];

const Toolbox: React.FC<ToolboxProps> = ({
    fontSize, onFontSizeChange,
    isAudioPlayerVisible,
    browsingMode, onBrowsingModeChange
}) => {
    const [isShown, setIsShown] = useState(true);
    const lastScrollY = useRef(0);

    // Effect to handle toolbox visibility on scroll
    useEffect(() => {
        const handleScroll = () => {
            const currentScrollY = window.scrollY;
            const scrollThreshold = 20;

            // Do nothing if scroll change is insignificant
            if (Math.abs(currentScrollY - lastScrollY.current) < scrollThreshold) {
                return;
            }

            if (currentScrollY < 100) { // Always show near the top
                setIsShown(true);
            } else if (currentScrollY > lastScrollY.current) { // Scrolling down
                setIsShown(false);
            } else { // Scrolling up
                setIsShown(true);
            }
            lastScrollY.current = currentScrollY;
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const handleIncreaseFont = () => {
        const currentIndex = FONT_SIZES.indexOf(fontSize);
        if (currentIndex < FONT_SIZES.length - 1) {
            onFontSizeChange(FONT_SIZES[currentIndex + 1]);
        }
    };

    const handleDecreaseFont = () => {
        const currentIndex = FONT_SIZES.indexOf(fontSize);
        if (currentIndex > 0) {
            onFontSizeChange(FONT_SIZES[currentIndex - 1]);
        }
    };

    const ToolButton: React.FC<{ onClick: () => void; label: string; children: React.ReactNode; isActive?: boolean; disabled?: boolean }> = ({ onClick, label, children, isActive, disabled }) => (
        <button
            onClick={onClick}
            disabled={disabled}
            aria-label={label}
            title={label}
            className={`p-3 rounded-full transition-colors ${isActive ? 'bg-surface-active text-primary-text-strong' : 'text-text-muted hover:bg-surface-hover'} ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
            {children}
        </button>
    );

    return (
        <div className={`fixed left-1/2 -translate-x-1/2 z-20 transition-all duration-300 ${isAudioPlayerVisible ? 'bottom-28' : 'bottom-8'}`}>
            <div className={`relative flex items-center gap-1 bg-surface/80 backdrop-blur-md p-2 rounded-full shadow-lg border border-border-default transition-all duration-300 ${
                isShown ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-16 pointer-events-none'
            }`}>

                {/* Navigation Group */}
                <ToolButton onClick={() => window.history.back()} label="الخلف"><ArrowRightIcon className="w-5 h-5" /></ToolButton>
                <ToolButton onClick={() => window.location.hash = '#/'} label="الرئيسية"><HomeIcon className="w-5 h-5" /></ToolButton>
                <ToolButton onClick={() => window.history.forward()} label="الأمام"><ArrowLeftIcon className="w-5 h-5" /></ToolButton>

                <div className="h-6 w-px bg-border-default mx-2"></div>

                {/* Font Size Group (Direct Control) */}
                <ToolButton 
                    onClick={handleDecreaseFont} 
                    label="تصغير الخط" 
                    disabled={fontSize === FONT_SIZES[0]}
                >
                    <MinusIcon className="w-5 h-5" />
                </ToolButton>

                <ToolButton 
                    onClick={handleIncreaseFont} 
                    label="تكبير الخط"
                    disabled={fontSize === FONT_SIZES[FONT_SIZES.length - 1]}
                >
                    <PlusIcon className="w-5 h-5" />
                </ToolButton>

                <div className="h-6 w-px bg-border-default mx-2"></div>

                {/* Browsing Mode Group */}
                <ToolButton
                    onClick={() => onBrowsingModeChange(browsingMode === 'full' ? 'page' : 'full')}
                    label={browsingMode === 'full' ? 'التحويل إلى عرض الصفحات' : 'التحويل إلى العرض الكامل'}
                >
                    {browsingMode === 'full' ? <DocumentDuplicateIcon className="w-5 h-5" /> : <QueueListIcon className="w-5 h-5" />}
                </ToolButton>

            </div>
        </div>
    );
};

export default Toolbox;

import React, { useState, useMemo, useCallback } from 'react';
import { MenuIcon, LogoIcon, SearchIcon, ArrowRightIcon, PlayIcon, SpinnerIcon, WifiOffIcon } from './icons';
import { QURAN_INDEX } from '../quranIndex';
import { formatSurahNameForDisplay } from '../utils/text';
import SearchForm from './SearchForm';
import ThemeToggleButton from './ThemeToggleButton';
import { useNetworkStatus } from '../hooks/useNetworkStatus';
import type { BrowsingMode, Ayah, FontStyleType } from '../types';

interface HeaderProps {
    setIsSidePanelOpen: (open: boolean) => void;
    currentPath: string;
    dataSourceStatus: 'primary' | 'fallback';
    // Props merged from ControlBar
    onSearch: (query: string) => void;
    searchDisabled: boolean;
    selectedEdition: string;
    setSelectedEdition: (edition: string) => void;
    fontStyle: FontStyleType;
    setFontStyle: (style: FontStyleType) => void;
    browsingMode: BrowsingMode;
    setBrowsingMode: (mode: BrowsingMode) => void;
    loadingEditions: string[];
    onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
    isPlaybackLoading: boolean;
    selectedAudioEdition: string;
}

const Logo: React.FC<{ dataSourceStatus: 'primary' | 'fallback'; isHomePage: boolean }> = ({ dataSourceStatus, isHomePage }) => {
    const [adminClickCount, setAdminClickCount] = useState(0);

    const handleLogoClick = () => {
        const newCount = adminClickCount + 1;
        setAdminClickCount(newCount);
        if (newCount >= 12) {
            window.location.hash = '#/admin';
            setAdminClickCount(0);
            return;
        }

        // Always navigate home on logo click
        window.location.hash = '#/';
    };

    const dotColorClass = dataSourceStatus === 'primary' ? 'text-green-500' : 'text-red-500';

    return (
        <div onClick={handleLogoClick} className="flex items-center gap-2 cursor-pointer select-none" title="الرجوع للرئيسية">
            <LogoIcon className="w-7 h-7 text-primary" />
            <span className="text-xl font-bold text-text-primary tracking-tighter">
                QRAN<span className={dotColorClass}>.</span>TOP
            </span>
        </div>
    );
};

const Header: React.FC<HeaderProps> = ({
    setIsSidePanelOpen,
    currentPath,
    dataSourceStatus,
    onSearch,
    searchDisabled,
    selectedEdition,
    setSelectedEdition,
    fontStyle,
    setFontStyle,
    setBrowsingMode,
    loadingEditions,
    onStartPlayback,
    isPlaybackLoading,
    selectedAudioEdition,
}) => {
    const [isMobileSearchOpen, setIsMobileSearchOpen] = useState(false);
    const isOnline = useNetworkStatus();

    const { pageTitle, isSurahOrPage, isRelevantPageForToggle, isSearchPage, isHomePage } = useMemo(() => {
        const path = currentPath.split('?')[0];
        const isHome = path === '#/';
        const isSearch = path.startsWith('#/search/');
        const isSurah = path.startsWith('#/surah/');
        const isPage = path.startsWith('#/page/');
        const isRelevant = isSurah || isPage || isSearch;

        let title = "QRAN.TOP";
        if (!isHome) {
            if (isSurah) {
                const surahNum = parseInt(path.split('/')[2], 10);
                const surah = QURAN_INDEX.find(s => s.number === surahNum);
                if (surah) title = formatSurahNameForDisplay(surah.name);
            } else if (isPage) {
                const pageNum = path.split('/')[2];
                title = `الصفحة ${pageNum}`;
            } else if (isSearch) {
                title = "نتائج البحث";
            }
        } else {
            title = "الفهرس";
        }

        return { 
            pageTitle: title, 
            isSurahOrPage: isSurah || isPage, 
            isRelevantPageForToggle: isRelevant,
            isSearchPage: isSearch,
            isHomePage: isHome
        };
    }, [currentPath]);

    const isUthmaniLoading = useMemo(() => {
        return loadingEditions.includes('quran-uthmani-quran-academy');
    }, [loadingEditions]);

    const handleStyleToggle = useCallback(() => {
        if (fontStyle === 'imlai_1') {
            setFontStyle('imlai_2');
            setSelectedEdition('quran-simple-clean');
            setBrowsingMode('full');
        } else if (fontStyle === 'imlai_2') {
            setFontStyle('uthmani');
            setSelectedEdition('quran-uthmani-quran-academy');
            setBrowsingMode('page');
        } else { // 'uthmani'
            setFontStyle('imlai_1');
            setSelectedEdition('quran-simple-clean');
            setBrowsingMode('full');
        }
    }, [fontStyle, setFontStyle, setSelectedEdition, setBrowsingMode]);

    const getToggleLabel = () => {
        if (isUthmaniLoading && fontStyle !== 'uthmani') return '...';
        switch (fontStyle) {
            case 'imlai_1': return 'إملائي 1';
            case 'imlai_2': return 'إملائي 2';
            case 'uthmani': return 'عثماني';
            default: return '...';
        }
    };

    const handlePlaySurah = useCallback(() => {
        if (!isOnline) {
            alert("عذراً، الاستماع للتلاوة يتطلب اتصالاً بالإنترنت.");
            return;
        }
        onStartPlayback([], selectedAudioEdition);
    }, [onStartPlayback, selectedAudioEdition, isOnline]);

    const handleSearchSubmit = (query: string) => {
        onSearch(query);
        setIsMobileSearchOpen(false);
    };

    const handleTitleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
        e.preventDefault();
        window.location.hash = '#/';
    };

    return (
        <header className="sticky top-0 z-30 bg-surface/90 backdrop-blur-md shadow-sm border-b border-border-default transition-all duration-300">
            <div className="w-full max-w-7xl mx-auto px-4">
                <div className="flex items-center justify-between h-16 gap-2">

                    {isMobileSearchOpen ? (
                        <div className="flex items-center w-full gap-2 animate-fade-in">
                            <button onClick={() => setIsMobileSearchOpen(false)} className="p-2 text-text-secondary hover:bg-surface-hover rounded-full">
                                <ArrowRightIcon className="w-6 h-6" />
                            </button>
                            <div className="flex-grow">
                                <SearchForm onSearch={handleSearchSubmit} disabled={searchDisabled} />
                            </div>
                        </div>
                    ) : (
                        <>
                            {/* Right Group (visually): Menu, Theme, Offline Indicator */}
                            <div className="flex items-center gap-1 sm:gap-2 flex-shrink-0">
                                <button
                                    onClick={() => setIsSidePanelOpen(true)}
                                    className="p-2 text-text-muted rounded-full hover:bg-surface-hover transition-colors"
                                    aria-label="فتح القائمة"
                                >
                                    <MenuIcon className="w-6 h-6" />
                                </button>
                                <ThemeToggleButton />
                                {!isOnline && (
                                    <div className="flex items-center justify-center p-2 rounded-full bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400" title="أنت غير متصل بالإنترنت. بعض الميزات قد لا تعمل.">
                                        <WifiOffIcon className="w-5 h-5" />
                                    </div>
                                )}
                            </div>

                            {/* Center Group: Title or Search */}
                            <div className="flex-grow flex justify-center min-w-0 px-2">
                                {/* Mobile Title */}
                                <div className="md:hidden text-lg font-bold text-text-primary truncate" title={pageTitle}>
                                     {isSearchPage ? (
                                        <a href="#/" onClick={handleTitleClick} className="hover:underline">{pageTitle}</a>
                                    ) : (
                                        pageTitle
                                    )}
                                </div>

                                {/* Desktop Search - Always Visible */}
                                <div className="hidden md:flex items-center w-full max-w-xl">
                                    <SearchForm onSearch={onSearch} disabled={searchDisabled} />
                                </div>
                            </div>

                            {/* Left Group (visually): Actions, Logo */}
                            <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
                                {isRelevantPageForToggle && (
                                    <button 
                                        onClick={handleStyleToggle}
                                        disabled={fontStyle !== 'uthmani' && isUthmaniLoading}
                                        className="px-2 py-1.5 text-xs md:text-sm md:px-3 font-semibold bg-surface-subtle text-text-secondary rounded-lg hover:bg-surface-hover transition-colors border border-border-default disabled:opacity-50"
                                        title="التبديل بين أوضاع العرض"
                                    >
                                        <span>{getToggleLabel()}</span>
                                    </button>
                                )}

                                {isSurahOrPage && (
                                    <button
                                        onClick={handlePlaySurah}
                                        disabled={isPlaybackLoading}
                                        className="hidden md:flex p-2 bg-primary text-white rounded-full shadow-md hover:bg-primary-hover transition-colors disabled:opacity-60"
                                        aria-label="استماع"
                                        title={!isOnline ? "غير متاح بدون إنترنت" : "استماع"}
                                    >
                                        {isPlaybackLoading ? <SpinnerIcon className="w-4 h-4"/> : <PlayIcon className="w-4 h-4"/>}
                                    </button>
                                )}

                                <button 
                                    onClick={() => setIsMobileSearchOpen(true)}
                                    className="md:hidden p-2 text-text-muted hover:text-primary hover:bg-surface-hover rounded-full"
                                    aria-label="بحث"
                                >
                                    <SearchIcon className="w-6 h-6" />
                                </button>

                                <div className="w-px h-6 bg-border-default mx-1"></div>

                                <Logo dataSourceStatus={dataSourceStatus} isHomePage={isHomePage} />
                            </div>
                        </>
                    )}
                </div>
            </div>
        </header>
    );
};

export default Header;

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import type { Ayah, QuranEdition, SurahData, FontSize, PlaybackMode, FontStyleType } from '../types';
import { useTheme } from '../hooks/useTheme';
import { useAudioKhatmiyah } from '../hooks/useAudioKhatmiyah';
import { 
    SpinnerIcon, PlayIcon, PauseIcon, ForwardIcon, BackwardIcon, 
    HomeIcon, BookOpenIcon, ComputerDesktopIcon, RepeatIcon,
    SunIcon, MoonIcon, ArrowsPointingOutIcon, ArrowsPointingInIcon
} from './icons';
import AudioEditionSelector from './AudioEditionSelector';
import JuzSelectionModal from './khatmiyah/JuzSelectionModal';
import PlaybackModeModal from './khatmiyah/PlaybackModeModal';
import SettingsModal from './khatmiyah/SettingsModal';
import SurahSelectionModal from './khatmiyah/SurahSelectionModal';
import { QURAN_INDEX } from '../quranIndex';

interface AudioKhatmiyahViewProps {
    allAyahs: Ayah[];
    allAudioEditions: QuranEdition[];
    initialAyahNumber: number;
    onSaveProgress: (ayahNumber: number) => void;
    selectedAudioEdition: string;
    onAudioEditionChange: (id: string) => void;
    allQuranData: { [key: string]: SurahData[] } | null;
    fetchCustomEditionData: (id: string) => void;
    activeEditions: QuranEdition[];
}

// --- Main Component ---
const AudioKhatmiyahView: React.FC<AudioKhatmiyahViewProps> = ({
    allAyahs, allAudioEditions, initialAyahNumber, onSaveProgress,
    selectedAudioEdition, onAudioEditionChange, allQuranData, fetchCustomEditionData,
    activeEditions
}) => {
    const { cycleTheme, emoji, name, nextThemeName, isDark } = useTheme();

    const [controlsVisible, setControlsVisible] = useState(true);
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isJuzSelectorOpen, setIsJuzSelectorOpen] = useState(false);
    const [isSurahSelectorOpen, setIsSurahSelectorOpen] = useState(false);
    const [isModeSelectorOpen, setIsModeSelectorOpen] = useState(false);
    const [juzModalMode, setJuzModalMode] = useState<'jump' | 'selection'>('jump');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Local state for display settings, specific to this view
    // Changed default to 'imlai_2' to avoid rendering issues (boxes) on some mobile devices
    const [khatmiyahFontStyle, setKhatmiyahFontStyle] = useState<FontStyleType>('imlai_2');
    const [khatmiyahFontSize, setKhatmiyahFontSize] = useState<FontSize>('xxl');

    const displayEditionIdentifier = useMemo(() => {
        return khatmiyahFontStyle === 'uthmani' ? 'quran-uthmani-quran-academy' : 'quran-simple-clean';
    }, [khatmiyahFontStyle]);

    const displayEditionDetails = useMemo(() => activeEditions.find(e => e.identifier === displayEditionIdentifier), [activeEditions, displayEditionIdentifier]);

    const juzStartAyahs = useMemo(() => {
        if (!allAyahs || allAyahs.length === 0) return [];
        const juzMap = new Map<number, number>();
        for (const ayah of allAyahs) {
            if (ayah.juz && !juzMap.has(ayah.juz)) {
                juzMap.set(ayah.juz, ayah.number);
            }
        }
        return Array.from(juzMap.entries())
            .sort((a, b) => a[0] - b[0])
            .map(([juz, ayahNumber]) => ({ juz, ayahNumber }));
    }, [allAyahs]);

    const {
        audioRef, currentAyah, displayedText, isPlaying, isLoading, isBuffering,
        audioDuration, audioProgress, currentWordIndex,
        handlePlayPause, handleNextAyah, handlePrevAyah, handleAudioEnded,
        setCurrentAyahNumber, setAudioDuration, setIsLoading, setIsBuffering, setIsPlaying,
        playbackMode, setPlaybackMode, 
        playbackJuzSelection, setPlaybackJuzSelection,
        playbackSurahSelection, setPlaybackSurahSelection,
        isLooping, setIsLooping
    } = useAudioKhatmiyah(
        allAyahs, initialAyahNumber, onSaveProgress, selectedAudioEdition, allAudioEditions,
        allQuranData, fetchCustomEditionData, displayEditionIdentifier, juzStartAyahs
    );

    const handleScreenTap = () => {
        if (isPlaying) setControlsVisible(prev => !prev);
    };

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => {
                setIsFullscreen(true);
            }).catch(err => {
                console.error(`Error attempting to enable fullscreen: ${err.message}`);
            });
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => {
                    setIsFullscreen(false);
                });
            }
        }
    };

    useEffect(() => {
        const handleFullscreenChange = () => {
            setIsFullscreen(!!document.fullscreenElement);
        };
        document.addEventListener('fullscreenchange', handleFullscreenChange);
        return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
    }, []);

    useEffect(() => {
        if (!isPlaying) setControlsVisible(true);
    }, [isPlaying]);

    useEffect(() => {
        if (!allQuranData?.[displayEditionIdentifier]) {
            fetchCustomEditionData(displayEditionIdentifier);
        }
    }, [displayEditionIdentifier, allQuranData, fetchCustomEditionData]);

    const handleJuzSelect = (ayahNumber: number) => {
        setCurrentAyahNumber(ayahNumber);
        setIsJuzSelectorOpen(false);
        if (!isPlaying) setIsPlaying(true);
    };

    const handleJuzSelectionConfirm = (selectedJuzs: number[]) => {
        if (selectedJuzs.length === 0) return;
        setPlaybackMode('selection_juz');
        setPlaybackJuzSelection(selectedJuzs);
        setPlaybackSurahSelection(null);
        const startAyahNumber = juzStartAyahs.find(j => j.juz === selectedJuzs[0])?.ayahNumber;
        if (startAyahNumber) {
            setCurrentAyahNumber(startAyahNumber);
        }
        setIsJuzSelectorOpen(false);
        if (!isPlaying) setIsPlaying(true);
    };

    const handleSurahSelectionConfirm = (selectedSurahs: number[]) => {
        if (selectedSurahs.length === 0) return;
        const sortedSurahs = selectedSurahs.sort((a, b) => a - b);
        setPlaybackMode('selection_surah');
        setPlaybackSurahSelection(sortedSurahs);
        setPlaybackJuzSelection(null);

        const firstSurahNumber = sortedSurahs[0];
        const firstAyahOfFirstSurah = allAyahs.find(a => a.surah?.number === firstSurahNumber && a.numberInSurah === 1);

        if (firstAyahOfFirstSurah) {
            setCurrentAyahNumber(firstAyahOfFirstSurah.number);
        }

        setIsSurahSelectorOpen(false);
        if (!isPlaying) setIsPlaying(true);
    };

    const getQuranTextStyle = useCallback(() => {
        let fontClass = 'imlai-font';
        if (khatmiyahFontStyle === 'imlai_2') {
            fontClass = 'scheherazade-font';
        } else if (khatmiyahFontStyle === 'uthmani') {
            fontClass = 'uthmani-font';
        }

        if (displayEditionDetails?.type === 'quran' && displayEditionDetails?.direction === 'rtl') {
            return {
                className: `${fontClass} quran-text-${khatmiyahFontSize}`,
            };
        }
        return { 
            className: `font-sans text-2xl md:text-3xl lg:text-4xl`, 
            style: { lineHeight: 1.8 } 
        };
    }, [displayEditionDetails, khatmiyahFontSize, khatmiyahFontStyle]);

    const { className: quranTextClass } = getQuranTextStyle();
    const canHighlight = displayEditionDetails?.type === 'quran' && displayEditionDetails?.direction === 'rtl';

    const formatJuzSelection = (juzs: number[]): string => {
        if (!juzs || juzs.length === 0) return '';
        if (juzs.length === 1) return `${juzs[0]}`;
        const sorted = [...juzs].sort((a,b) => a - b);
        const ranges: string[] = [];
        let start = sorted[0]; let end = sorted[0];
        for (let i = 1; i < sorted.length; i++) {
            if (sorted[i] === end + 1) end = sorted[i];
            else { ranges.push(start === end ? `${start}` : `${start}-${end}`); start = sorted[i]; end = sorted[i]; }
        }
        ranges.push(start === end ? `${start}` : `${start}-${end}`);
        return ranges.join(', ');
    };

    const getPlaybackScopeDescription = () => {
        if (playbackMode === 'single' && currentAyah?.juz) return `الجزء ${currentAyah.juz} فقط`;
        if (playbackMode === 'selection_juz' && playbackJuzSelection) {
            const isRange = playbackJuzSelection.every((juz, i) => i === 0 || juz === playbackJuzSelection[i-1] + 1);
            if (isRange && playbackJuzSelection.length > 1) return `من الجزء ${playbackJuzSelection[0]} إلى ${playbackJuzSelection[playbackJuzSelection.length - 1]}`;
            return `أجزاء مختارة: ${formatJuzSelection(playbackJuzSelection)}`;
        }
        if (playbackMode === 'selection_surah' && playbackSurahSelection) {
            if (playbackSurahSelection.length > 2) {
                return `${playbackSurahSelection.length} سور مختارة`;
            }
            const surahNames = playbackSurahSelection.map(num => QURAN_INDEX.find(s => s.number === num)?.name.replace('سُورَةُ ', '')).filter(Boolean).join('، ');
            return `سور مختارة: ${surahNames}`;
        }
        return 'ختمة كاملة';
    };

    if (!currentAyah) {
        return <div className="flex flex-col gap-4 justify-center items-center h-screen bg-gray-900 text-white"><SpinnerIcon className="w-10 h-10"/> <p>جاري تحميل بيانات الختمة...</p></div>;
    }

    return (
        <div className="bg-background text-text-primary fixed inset-0 flex flex-col font-sans" onClick={handleScreenTap}>
            {isJuzSelectorOpen && <JuzSelectionModal onClose={() => setIsJuzSelectorOpen(false)} juzStartAyahs={juzStartAyahs} onJuzSelect={handleJuzSelect} onSelectionConfirm={handleJuzSelectionConfirm} mode={juzModalMode} />}
            {isSurahSelectorOpen && <SurahSelectionModal onClose={() => setIsSurahSelectorOpen(false)} onSelectionConfirm={handleSurahSelectionConfirm} />}
            {isModeSelectorOpen && <PlaybackModeModal onClose={() => setIsModeSelectorOpen(false)} onModeSelect={(mode: PlaybackMode) => { setPlaybackMode(mode); setPlaybackJuzSelection(null); setPlaybackSurahSelection(null); if (mode === 'single' && !isPlaying) setIsPlaying(true); }} onJuzSelectionStart={() => { setIsModeSelectorOpen(false); setJuzModalMode('selection'); setIsJuzSelectorOpen(true); }} onSurahSelectionStart={() => { setIsModeSelectorOpen(false); setIsSurahSelectorOpen(true); }} />}
            {isSettingsOpen && <SettingsModal onClose={() => setIsSettingsOpen(false)} fontSize={khatmiyahFontSize} onFontSizeChange={setKhatmiyahFontSize} fontStyle={khatmiyahFontStyle} onFontStyleChange={setKhatmiyahFontStyle} />}

            <audio ref={audioRef} onLoadedMetadata={() => setAudioDuration(audioRef.current?.duration || 0)} onCanPlay={() => { setIsLoading(false); setIsBuffering(false); if(isPlaying) audioRef.current?.play(); }} onPlay={() => setIsPlaying(true)} onPause={() => { if (audioRef.current && Math.abs(audioRef.current.currentTime - audioRef.current.duration) > 0.1) setIsPlaying(false); }} onEnded={handleAudioEnded} onWaiting={() => setIsBuffering(true)} className="hidden" />

            <header className={`flex-shrink-0 p-3 flex items-center justify-between bg-surface/80 backdrop-blur-md shadow-md z-10 transition-all duration-300 ${controlsVisible ? 'opacity-100' : 'opacity-0 -translate-y-full'}`}>
                {/* Right Group (RTL): Home */}
                <div className="flex-shrink-0">
                    <a href="#/" onClick={(e) => { e.preventDefault(); window.location.hash = '#/'; }} title="العودة للرئيسية" aria-label="العودة للرئيسية" className="p-2 rounded-full bg-surface-subtle hover:bg-surface-hover block text-text-secondary">
                        <HomeIcon className="w-6 h-6"/>
                    </a>
                </div>

                <div className="text-center">
                    <h1 className="text-xl font-bold text-primary-text-strong">سورة {currentAyah.surah?.name}</h1>
                    <div className="text-sm text-text-muted font-semibold flex justify-center gap-4">
                        <span>الآية: {currentAyah.numberInSurah}</span>
                        <span>الجزء: {currentAyah.juz}</span>
                        <span>الصفحة: {currentAyah.page}</span>
                    </div>
                </div>

                {/* Left Group (RTL): Actions (Theme, Fullscreen) */}
                <div className="flex items-center gap-2 flex-shrink-0">
                    <button 
                        onClick={cycleTheme}
                        className="p-2 rounded-full bg-surface-subtle hover:bg-surface-hover text-text-secondary"
                        title="تغيير المظهر"
                    >
                        {isDark ? <SunIcon className="w-6 h-6 text-yellow-400" /> : <MoonIcon className="w-6 h-6" />}
                    </button>
                    <button 
                        onClick={toggleFullscreen}
                        className="p-2 rounded-full bg-surface-subtle hover:bg-surface-hover text-text-secondary"
                        title={isFullscreen ? "إنهاء ملء الشاشة" : "ملء الشاشة"}
                    >
                        {isFullscreen ? <ArrowsPointingInIcon className="w-6 h-6" /> : <ArrowsPointingOutIcon className="w-6 h-6" />}
                    </button>
                </div>
            </header>

            <main className="flex-grow flex items-center justify-center p-4">
                <div className="text-center w-full">
                    {(isLoading && !displayedText) ? <div className="flex flex-col gap-4 items-center"><SpinnerIcon className="w-12 h-12 text-primary"/><p className="text-lg">جاري تحميل الآية...</p></div>
                    : <p className={`select-none ${quranTextClass}`} dir={displayEditionDetails?.direction || 'rtl'}>
                        {canHighlight 
                            ? displayedText.trim().split(/\s+/).map((word, index) => <span key={index} className={`transition-colors duration-200 ${index === currentWordIndex ? 'text-primary' : ''}`}>{word}{' '}</span>) 
                            : displayedText}
                       </p>}
                </div>
            </main>

            <footer className={`flex-shrink-0 p-4 bg-surface/80 backdrop-blur-md shadow-[0_-4px_30px_rgba(0,0,0,0.1)] z-10 transition-all duration-300 ${controlsVisible ? 'opacity-100' : 'opacity-0 translate-y-full'}`}>
                <div className="w-full h-1.5 bg-surface-subtle rounded-full mb-4"><div className="h-1.5 bg-primary rounded-full transition-all" style={{ width: audioDuration > 0 ? `${(audioProgress / audioDuration) * 100}%` : '0%'}}></div></div>
                <div className="flex items-center justify-between gap-4">
                    <div className="flex-1 min-w-0 flex flex-col gap-1 items-start">
                        <AudioEditionSelector audioEditions={allAudioEditions} selectedAudioEdition={selectedAudioEdition} onSelect={onAudioEditionChange} size="sm" />
                        <span className="text-xs font-semibold text-text-muted px-2">{getPlaybackScopeDescription()}</span>
                    </div>

                    {/* Controls Center */}
                    <div className="flex items-center gap-2 sm:gap-4 flex-shrink-0">
                        <button onClick={handlePrevAyah} className="p-2 text-text-secondary hover:text-text-primary transition-colors"><BackwardIcon className="w-7 h-7" /></button>
                        <button onClick={handlePlayPause} className="p-4 bg-primary text-white rounded-full shadow-lg hover:bg-primary-hover transition-transform hover:scale-105">
                             {isBuffering ? <SpinnerIcon className="w-8 h-8"/> : (isPlaying ? <PauseIcon className="w-8 h-8" /> : <PlayIcon className="w-8 h-8" />)}
                        </button>
                        <button onClick={handleNextAyah} className="p-2 text-text-secondary hover:text-text-primary transition-colors"><ForwardIcon className="w-7 h-7" /></button>
                    </div>

                    {/* Controls Left */}
                    <div className="flex-1 flex justify-end items-center gap-2">
                        <button 
                            onClick={() => setIsLooping(!isLooping)} 
                            title={isLooping ? "إيقاف تكرار السورة" : "تكرار السورة"} 
                            className={`p-2 rounded-full transition-colors ${isLooping ? 'text-primary bg-primary/10' : 'text-text-muted hover:bg-surface-hover'}`}
                        >
                            <RepeatIcon className="w-6 h-6"/>
                        </button>
                        <div className="h-6 w-px bg-border-default mx-1"></div>
                        <button onClick={() => { setIsModeSelectorOpen(true); }} title="تحديد نطاق القراءة" className={`p-2 rounded-full transition-colors text-text-muted hover:bg-surface-hover`}><BookOpenIcon className="w-6 h-6"/></button>
                        <button onClick={() => setIsSettingsOpen(true)} title="إعدادات العرض" className="p-2 rounded-full text-text-muted hover:bg-surface-hover transition-colors"><ComputerDesktopIcon className="w-6 h-6"/></button>
                    </div>
                </div>
            </footer>
        </div>
    );
};

